const e=JSON.parse(`[{"id":1,"section":"A","theme":"Objets de la vie quotidienne","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un réveil qui sonne","image_prompt":"A classic alarm clock ringing on a bedside table, morning light"},{"id":"B","text":"Une cafetière qui gargouille","image_prompt":"A coffee maker brewing fresh coffee, steam rising"},{"id":"C","text":"Un grille-pain qui saute","image_prompt":"A toaster popping up golden toast slices"},{"id":"D","text":"Une bouilloire qui siffle","image_prompt":"A whistling kettle on a stove, steam coming out"}],"correct":1,"transcript_fr":"Attention, il est déjà huit heures moins le quart. Vous devez vous dépêcher pour ne pas être en retard au travail.","transcript_en":"Attention, it's already a quarter to eight. You need to hurry so you won't be late for work.","points":[{"point":1,"male_lines":["Attention, il est déjà huit heures moins le quart.","Vous devez vous dépêcher pour ne pas être en retard au travail."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Météo et climat","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un soleil brillant","image_prompt":"Bright yellow sun shining in clear blue sky"},{"id":"B","text":"Des nuages gris et de la pluie","image_prompt":"Dark grey storm clouds with heavy rain falling"},{"id":"C","text":"De la neige qui tombe","image_prompt":"Heavy snowfall covering trees and ground in white"},{"id":"D","text":"Du brouillard épais","image_prompt":"Thick fog covering a city street, low visibility"}],"correct":2,"transcript_fr":"Prévisions météo pour demain : attendez-vous à des températures sous zéro avec des précipitations neigeuses toute la journée. Conduisez prudemment.","transcript_en":"Weather forecast for tomorrow: expect below zero temperatures with snowy precipitation all day long. Drive carefully.","points":[{"point":1,"male_lines":["Prévisions météo pour demain : attendez-vous à des températures sous zéro avec des précipitations neigeuses toute la journée.","Conduisez prudemment."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Transport et déplacements","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un autobus qui arrive à l'arrêt","image_prompt":"A city bus arriving at a bus stop with passengers waiting"},{"id":"B","text":"Un train qui entre en gare","image_prompt":"A commuter train pulling into a station platform"},{"id":"C","text":"Un avion qui décolle","image_prompt":"A commercial airplane taking off from a runway"},{"id":"D","text":"Un bateau qui accoste","image_prompt":"A ferry boat docking at a harbor pier"}],"correct":0,"transcript_fr":"Prochain arrêt : station Berri-UQAM. Attention à la fermeture des portes. La correspondance vers la ligne verte est disponible sur le quai central.","transcript_en":"Next stop: Berri-UQAM station. Watch the doors closing. Transfer to the green line is available on the central platform.","points":[{"point":1,"male_lines":["Prochain arrêt : station Berri-UQAM.","Attention à la fermeture des portes. La correspondance vers la ligne verte est disponible sur le quai central."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Nourriture et cuisine","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une pizza dans un four","image_prompt":"A pizza baking in a hot oven, cheese melting"},{"id":"B","text":"Un gâteau au chocolat","image_prompt":"A rich chocolate cake with frosting on a plate"},{"id":"C","text":"Une soupe qui bout","image_prompt":"Soup boiling in a pot with vegetables visible"},{"id":"D","text":"Des crêpes sur une poêle","image_prompt":"Golden crepes cooking on a flat frying pan"}],"correct":3,"transcript_fr":"Pour la Chandeleur, ma grand-mère prépare toujours des crêpes fines et légères. Elle les fait sauter haut dans la poêle avec une technique parfaite.","transcript_en":"For Candlemas, my grandmother always prepares thin and light crepes. She flips them high in the pan with perfect technique.","points":[{"point":1,"male_lines":["Pour la Chandeleur, ma grand-mère prépare toujours des crêpes fines et légères.","Elle les fait sauter haut dans la poêle avec une technique parfaite."],"female_lines":[]}]},{"id":5,"section":"A","theme":"Achats et commerce","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un caissier qui scanne des articles","image_prompt":"A cashier scanning grocery items at a checkout counter"},{"id":"B","text":"Un client qui essaie des vêtements","image_prompt":"A customer trying on clothes in a fitting room mirror"},{"id":"C","text":"Un vendeur qui conseille un client","image_prompt":"A salesperson advising a customer in an electronics store"},{"id":"D","text":"Des sacs de courses pleins","image_prompt":"Full shopping bags carried by a person leaving a store"}],"correct":0,"transcript_fr":"Bonjour,avez-vous la carte de fidélité ? Cet article est en promotion aujourd'hui seulement. Voulez-vous un sac réutilisable pour cinquante cents de plus ?","transcript_en":"Hello, do you have the loyalty card? This item is on promotion today only. Would you like a reusable bag for fifty cents more?","points":[{"point":1,"male_lines":["Bonjour, avez-vous la carte de fidélité ?","Cet article est en promotion aujourd'hui seulement. Voulez-vous un sac réutilisable pour cinquante cents de plus ?"],"female_lines":[]}]},{"id":6,"section":"A","theme":"Loisirs et sports","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Des gens qui font du ski","image_prompt":"People skiing down a snowy mountain slope"},{"id":"B","text":"Des personnes qui patinent","image_prompt":"People ice skating on an outdoor frozen rink"},{"id":"C","text":"Des cyclistes sur une piste","image_prompt":"Cyclists riding on a dedicated bike path in a park"},{"id":"D","text":"Des nageurs dans une piscine","image_prompt":"Swimmers doing laps in an Olympic-size swimming pool"}],"correct":1,"transcript_fr":"La patinoire du Vieux-Port ouvre ses portes ce weekend. Location de patins disponible sur place. Attention aux heures de fermeture à vingt-deux heures.","transcript_en":"The Old Port ice rink opens its doors this weekend. Skate rental available on site. Watch for closing time at ten PM.","points":[{"point":1,"male_lines":["La patinoire du Vieux-Port ouvre ses portes ce weekend.","Location de patins disponible sur place. Attention aux heures de fermeture à vingt-deux heures."],"female_lines":[]}]},{"id":7,"section":"B","theme":"Rendez-vous médical","question":"Que demande la femme ?","options":[{"id":"A","text":"Elle veut annuler son rendez-vous","image_prompt":"A woman on the phone looking concerned"},{"id":"B","text":"Elle souhaite déplacer son rendez-vous","image_prompt":"A woman checking her calendar schedule"},{"id":"C","text":"Elle demande l'adresse du cabinet","image_prompt":"A woman looking at a map on her phone"},{"id":"D","text":"Elle veut connaître les tarifs","image_prompt":"A woman holding money and a medical bill"}],"correct":1,"transcript_fr":"HOMME : Clinique médicale Saint-Laurent, bonjour. FEMME : Bonjour, c'est Madame Tremblay. J'ai un rendez-vous demain à quatorze heures avec le Dr. Martin. HOMME : Oui, je vois votre dossier. Que puis-je faire pour vous ? FEMME : Malheureusement, quelque chose d'urgent est survenu au travail. Est-ce possible de reporter à vendredi même heure ? HOMME : Attendez, je vérifie les disponibilités. Oui, vendredi quatorze heures fonctionne. Je modifie votre rendez-vous. FEMME : Merci beaucoup, vous êtes très aimable. HOMME : Pas de problème, Madame Tremblay. À vendredi.","transcript_en":"MAN: Saint-Laurent Medical Clinic, hello. WOMAN: Hello, this is Mrs. Tremblay. I have an appointment tomorrow at two PM with Dr. Martin. MAN: Yes, I see your file. What can I do for you? WOMAN: Unfortunately, something urgent came up at work. Is it possible to postpone to Friday same time? MAN: Wait, let me check availability. Yes, Friday two PM works. I'll modify your appointment. WOMAN: Thank you very much, you're very kind. MAN: No problem, Mrs. Tremblay. See you Friday.","points":[{"point":1,"male_lines":["Clinique médicale Saint-Laurent, bonjour.","Oui, je vois votre dossier. Que puis-je faire pour vous ?"],"female_lines":["Bonjour, c'est Madame Tremblay. J'ai un rendez-vous demain à quatorze heures avec le Dr. Martin.","Malheureusement, quelque chose d'urgent est survenu au travail."]},{"point":2,"male_lines":["Attendez, je vérifie les disponibilités.","Oui, vendredi quatorze heures fonctionne. Je modifie votre rendez-vous."],"female_lines":["Est-ce possible de reporter à vendredi même heure ?","Merci beaucoup, vous êtes très aimable."]}]},{"id":8,"section":"B","theme":"Réservation de restaurant","question":"Combien de personnes le couple souhaite-t-il réserver ?","options":[{"id":"A","text":"Deux personnes","image_prompt":"A table for two in a romantic restaurant"},{"id":"B","text":"Quatre personnes","image_prompt":"A table set for four people with menus"},{"id":"C","text":"Six personnes","image_prompt":"A large round table with six chairs"},{"id":"D","text":"Huit personnes","image_prompt":"A long rectangular table for eight guests"}],"correct":1,"transcript_fr":"FEMME : Bonjour, restaurant Chez Pierre, j'écoute. HOMME : Bonjour, je voudrais réserver une table pour samedi soir. FEMME : Très bien, pour combien de personnes ? HOMME : Nous serons quatre adultes et deux enfants, donc six personnes au total. FEMME : D'accord, et à quelle heure souhaitez-vous venir ? HOMME : Vers dix-neuf heures trente, c'est possible ? FEMME : Dix-neuf heures trente, c'est parfait. Quel est votre nom ? HOMME : C'est Gagnon, Marc Gagnon. FEMME : Parfait, Monsieur Gagnon. Votre table est réservée pour samedi à dix-neuf heures trente pour six personnes.","transcript_en":"WOMAN: Hello, Chez Pierre restaurant, I'm listening. MAN: Hello, I would like to reserve a table for Saturday evening. WOMAN: Very well, for how many people? MAN: We will be four adults and two children, so six people total. WOMAN: Okay, and what time would you like to come? MAN: Around seven thirty PM, is that possible? WOMAN: Seven thirty PM is perfect. What is your name? MAN: It's Gagnon, Marc Gagnon. WOMAN: Perfect, Mr. Gagnon. Your table is reserved for Saturday at seven thirty PM for six people.","points":[{"point":1,"male_lines":["Bonjour, je voudrais réserver une table pour samedi soir.","Nous serons quatre adultes et deux enfants, donc six personnes au total."],"female_lines":["Bonjour, restaurant Chez Pierre, j'écoute.","Très bien, pour combien de personnes ?"]},{"point":2,"male_lines":["Vers dix-neuf heures trente, c'est possible ?","C'est Gagnon, Marc Gagnon."],"female_lines":["D'accord, et à quelle heure souhaitez-vous venir ?","Parfait, Monsieur Gagnon. Votre table est réservée pour samedi à dix-neuf heures trente pour six personnes."]}]},{"id":9,"section":"B","theme":"Problème de voiture","question":"Quel est le problème de la voiture ?","options":[{"id":"A","text":"Le moteur ne démarre pas","image_prompt":"A car with hood open and mechanic checking engine"},{"id":"B","text":"Les freins ne fonctionnent plus","image_prompt":"A car brake system being repaired in garage"},{"id":"C","text":"La batterie est morte","image_prompt":"A car battery with jumper cables attached"},{"id":"D","text":"Le pneu est crevé","image_prompt":"A flat tire on a car with spare tire visible"}],"correct":3,"transcript_fr":"FEMME : Allo, Marc ? C'est Julie. J'ai un problème avec la voiture. HOMME : Qu'est-ce qui se passe ? Tu es où ? FEMME : Je suis sur l'autoroute quinze, près de la sortie Laval. Je crois que j'ai crevé un pneu. HOMME : Es-tu en sécurité sur le bas-côté ? FEMME : Oui, j'ai mis les feux de détresse. Mais je n'ai jamais changé de roue de ma vie. HOMME : Ne t'inquiète pas, je viens te chercher. Où exactement ? FEMME : Au kilomètre trente-deux, côté nord. HOMME : D'accord, je pars tout de suite. Je serai là dans vingt minutes.","transcript_en":"WOMAN: Hello, Marc? It's Julie. I have a problem with the car. MAN: What's happening? Where are you? WOMAN: I'm on highway fifteen, near the Laval exit. I think I have a flat tire. MAN: Are you safe on the shoulder? WOMAN: Yes, I put the hazard lights on. But I've never changed a tire in my life. MAN: Don't worry, I'll come get you. Where exactly? WOMAN: At kilometer thirty-two, north side. MAN: Okay, I'm leaving right now. I'll be there in twenty minutes.","points":[{"point":1,"male_lines":["Qu'est-ce qui se passe ? Tu es où ?","Es-tu en sécurité sur le bas-côté ?"],"female_lines":["Allo, Marc ? C'est Julie. J'ai un problème avec la voiture.","Je suis sur l'autoroute quinze, près de la sortie Laval. Je crois que j'ai crevé un pneu."]},{"point":2,"male_lines":["Ne t'inquiète pas, je viens te chercher. Où exactement ?","D'accord, je pars tout de suite. Je serai là dans vingt minutes."],"female_lines":["Oui, j'ai mis les feux de détresse. Mais je n'ai jamais changé de roue de ma vie.","Au kilomètre trente-deux, côté nord."]}]},{"id":10,"section":"B","theme":"Demande de renseignements","question":"Où se déroule la conversation ?","options":[{"id":"A","text":"Dans une bibliothèque","image_prompt":"Interior of a public library with bookshelves"},{"id":"B","text":"Dans une pharmacie","image_prompt":"Interior of a pharmacy with medicine shelves"},{"id":"C","text":"Dans une banque","image_prompt":"Interior of a bank with teller counters"},{"id":"D","text":"Dans un bureau de poste","image_prompt":"Interior of a post office with mail counters"}],"correct":0,"transcript_fr":"HOMME : Bonjour, excusez-moi. Je cherche le rayon des romans québécois. FEMME : Bonjour, les romans québécois sont au deuxième étage, section gauche. HOMME : Merci. Et est-ce que je peux emprunter un ordinateur portable pour travailler ? FEMME : Oui, il y a des portables disponibles au comptoir des prêts. Il faut juste présenter votre carte de bibliothèque. HOMME : Parfait. Une dernière question : la bibliothèque ferme à quelle heure aujourd'hui ? FEMME : Nous fermons à vingt et une heures ce soir. HOMME : Excellent, j'ai encore trois heures devant moi. Merci beaucoup.","transcript_en":"MAN: Hello, excuse me. I'm looking for the Quebec novels section. WOMAN: Hello, Quebec novels are on the second floor, left section. MAN: Thank you. And can I borrow a laptop to work? WOMAN: Yes, there are laptops available at the loan counter. You just need to present your library card. MAN: Perfect. One last question: what time does the library close today? WOMAN: We close at nine PM tonight. MAN: Excellent, I still have three hours ahead of me. Thank you very much.","points":[{"point":1,"male_lines":["Bonjour, excusez-moi. Je cherche le rayon des romans québécois.","Merci. Et est-ce que je peux emprunter un ordinateur portable pour travailler ?"],"female_lines":["Bonjour, les romans québécois sont au deuxième étage, section gauche.","Oui, il y a des portables disponibles au comptoir des prêts. Il faut juste présenter votre carte de bibliothèque."]},{"point":2,"male_lines":["Parfait. Une dernière question : la bibliothèque ferme à quelle heure aujourd'hui ?","Excellent, j'ai encore trois heures devant moi. Merci beaucoup."],"female_lines":["Nous fermons à vingt et une heures ce soir.",""]}]},{"id":11,"section":"C","theme":"Annonce de travaux","question":"Quelle rue sera fermée et pour combien de temps ?","options":[{"id":"A","text":"La rue Saint-Denis pendant trois jours","image_prompt":"Street closed sign on Saint-Denis street with construction barriers"},{"id":"B","text":"L'avenue du Mont-Royal pendant une semaine","image_prompt":"Construction work on Mont-Royal avenue with detour signs"},{"id":"C","text":"Le boulevard René-Lévesque pendant deux semaines","image_prompt":"Major road closure on René-Lévesque boulevard with heavy machinery"},{"id":"D","text":"La rue Sainte-Catherine pendant un mois","image_prompt":"Long-term construction on Sainte-Catherine street with scaffolding"}],"correct":1,"transcript_fr":"Point 1 : Attention aux automobilistes, la ville de Montréal annonce des travaux majeurs sur l'avenue du Mont-Royal. Point 2 : La circulation sera complètement interrompue entre la rue Saint-Denis et le boulevard Saint-Laurent. Point 3 : Ces travaux de réfection de la chaussée débuteront lundi prochain et dureront sept jours complets. Point 4 : Une déviation sera mise en place via la rue Rachel et la rue Sherbrooke. Point 5 : Les autobus des lignes onze et quatre-vingt-dix-sept seront détournés. Point 6 : La STM recommande aux usagers de prévoir quinze minutes supplémentaires pour leurs déplacements. Point 7 : Les commerçants de l'avenue resteront accessibles par les rues transversales. Point 8 : Des panneaux indicateurs seront installés dès ce weekend. Point 9 : La ville présente ses excuses pour la gêne occasionnée. Point 10 : Pour plus d'informations, consultez le site ville point montréal point qc point ca.","transcript_en":"Point 1: Attention drivers, the city of Montreal announces major work on Mont-Royal avenue. Point 2: Traffic will be completely interrupted between Saint-Denis street and Saint-Laurent boulevard. Point 3: These road resurfacing works will begin next Monday and will last seven full days. Point 4: A detour will be set up via Rachel street and Sherbrooke street. Point 5: Buses on lines eleven and ninety-seven will be diverted. Point 6: The STM recommends users to plan fifteen extra minutes for their trips. Point 7: Avenue merchants will remain accessible via cross streets. Point 8: Directional signs will be installed starting this weekend. Point 9: The city apologizes for the inconvenience caused. Point 10: For more information, visit ville dot montreal dot qc dot ca.","points":[{"point":1,"male_lines":["Attention aux automobilistes, la ville de Montréal annonce des travaux majeurs sur l'avenue du Mont-Royal.","La circulation sera complètement interrompue entre la rue Saint-Denis et le boulevard Saint-Laurent."],"female_lines":["",""]},{"point":2,"male_lines":["Ces travaux de réfection de la chaussée débuteront lundi prochain et dureront sept jours complets.","Une déviation sera mise en place via la rue Rachel et la rue Sherbrooke."],"female_lines":["",""]},{"point":3,"male_lines":["Les autobus des lignes onze et quatre-vingt-dix-sept seront détournés.","La STM recommande aux usagers de prévoir quinze minutes supplémentaires pour leurs déplacements."],"female_lines":["",""]},{"point":4,"male_lines":["Les commerçants de l'avenue resteront accessibles par les rues transversales.","Des panneaux indicateurs seront installés dès ce weekend."],"female_lines":["",""]},{"point":5,"male_lines":["La ville présente ses excuses pour la gêne occasionnée.","Pour plus d'informations, consultez le site ville point montréal point qc point ca."],"female_lines":["",""]}]},{"id":12,"section":"C","theme":"Message de la sécurité publique","question":"Quel type d'alerte est diffusé ?","options":[{"id":"A","text":"Alerte météo tempête de verglas","image_prompt":"Ice storm warning with frozen trees and power lines"},{"id":"B","text":"Alerte qualité de l'air","image_prompt":"Smog alert over city skyline with air quality warning"},{"id":"C","text":"Alerte ébullition d'eau","image_prompt":"Boil water advisory notice with kitchen tap running"},{"id":"D","text":"Alerte feu de forêt","image_prompt":"Forest fire warning with smoke visible in distance"}],"correct":2,"transcript_fr":"Point 1 : Avis important de la Ville de Laval concernant la qualité de l'eau potable. Point 2 : Suite à des travaux sur la conduite principale de la rue Notre-Dame, une contamination bactériologique a été détectée. Point 3 : Tous les résidents du secteur Chomedey doivent faire bouillir leur eau pendant au moins une minute avant consommation. Point 4 : Cette mesure s'applique à l'eau utilisée pour boire, préparer des aliments et se brosser les dents. Point 5 : L'eau du robinet peut toujours être utilisée pour la douche et la lessive. Point 6 : Des camions-citernes sont stationnés à l'aréna Martin-St-Louis pour distribuer de l'eau potable. Point 7 : Les tests de laboratoire devraient confirmer la qualité de l'eau d'ici quarante-huit heures. Point 8 : Évitez de donner cette eau non bouillie aux nourrissons et aux personnes immunodéprimées. Point 9 : Pour toute question, composez le trois-un-un. Point 10 : Merci de votre compréhension et de votre coopération.","transcript_en":"Point 1: Important notice from the City of Laval regarding drinking water quality. Point 2: Following work on the main pipe on Notre-Dame street, bacterial contamination was detected. Point 3: All residents of the Chomedey sector must boil their water for at least one minute before consumption. Point 4: This measure applies to water used for drinking, preparing food, and brushing teeth. Point 5: Tap water can still be used for showering and laundry. Point 6: Water tanker trucks are stationed at the Martin-St-Louis arena to distribute drinking water. Point 7: Laboratory tests should confirm water quality within forty-eight hours. Point 8: Avoid giving this unboiled water to infants and immunocompromised persons. Point 9: For any questions, dial three-one-one. Point 10: Thank you for your understanding and cooperation.","points":[{"point":1,"male_lines":["Avis important de la Ville de Laval concernant la qualité de l'eau potable.","Suite à des travaux sur la conduite principale de la rue Notre-Dame, une contamination bactériologique a été détectée."],"female_lines":["",""]},{"point":2,"male_lines":["Tous les résidents du secteur Chomedey doivent faire bouillir leur eau pendant au moins une minute avant consommation.","Cette mesure s'applique à l'eau utilisée pour boire, préparer des aliments et se brosser les dents."],"female_lines":["",""]},{"point":3,"male_lines":["L'eau du robinet peut toujours être utilisée pour la douche et la lessive.","Des camions-citernes sont stationnés à l'aréna Martin-St-Louis pour distribuer de l'eau potable."],"female_lines":["",""]},{"point":4,"male_lines":["Les tests de laboratoire devraient confirmer la qualité de l'eau d'ici quarante-huit heures.","Évitez de donner cette eau non bouillie aux nourrissons et aux personnes immunodéprimées."],"female_lines":["",""]},{"point":5,"male_lines":["Pour toute question, composez le trois-un-un.","Merci de votre compréhension et de votre coopération."],"female_lines":["",""]}]},{"id":13,"section":"C","theme":"Annonce d'événement culturel","question":"Quel est le prix des billets pour les enfants ?","options":[{"id":"A","text":"Gratuit pour les moins de douze ans","image_prompt":"Free admission sign for children under twelve at cultural event"},{"id":"B","text":"Cinq dollars pour les enfants","image_prompt":"Five dollar ticket price sign for children"},{"id":"C","text":"Dix dollars pour les enfants","image_prompt":"Ten dollar children ticket at museum entrance"},{"id":"D","text":"Quinze dollars pour tous les âges","image_prompt":"Fifteen dollar general admission sign for all ages"}],"correct":0,"transcript_fr":"Point 1 : Le Musée des beaux-arts de Montréal présente l'exposition « Les impressionnistes » dès ce samedi. Point 2 : Cette exposition exceptionnelle regroupe plus de quatre-vingts œuvres majeures du mouvement impressionniste. Point 3 : Les horaires d'ouverture sont de dix heures à dix-sept heures du mardi au dimanche. Point 4 : L'entrée est gratuite pour les enfants de moins de douze ans accompagnés d'un adulte. Point 5 : Pour les adultes, le tarif est de vingt-deux dollars, tarif réduit à quinze dollars pour les étudiants et aînés. Point 6 : Des visites guidées sont offertes tous les jours à onze heures et quatorze heures. Point 7 : Un audioguide est inclus dans le prix du billet et disponible en français et en anglais. Point 8 : Le café du musée propose un menu spécial « pause artistique » pendant toute la durée de l'exposition. Point 9 : L'exposition se termine le quinze mars prochain, ne manquez pas cette occasion unique. Point 10 : Réservez vos billets en ligne sur mbam point qc point ca pour éviter les files d'attente.","transcript_en":"Point 1: The Montreal Museum of Fine Arts presents the exhibition « The Impressionists » starting this Saturday. Point 2: This exceptional exhibition brings together more than eighty major works of the Impressionist movement. Point 3: Opening hours are from ten AM to five PM Tuesday through Sunday. Point 4: Admission is free for children under twelve accompanied by an adult. Point 5: For adults, the rate is twenty-two dollars, reduced rate of fifteen dollars for students and seniors. Point 6: Guided tours are offered every day at eleven AM and two PM. Point 7: An audio guide is included in the ticket price and available in French and English. Point 8: The museum café offers a special « artistic break » menu throughout the exhibition duration. Point 9: The exhibition ends next March fifteenth, don't miss this unique opportunity. Point 10: Book your tickets online at mbam dot qc dot ca to avoid waiting lines.","points":[{"point":1,"male_lines":["Le Musée des beaux-arts de Montréal présente l'exposition « Les impressionnistes » dès ce samedi.","Cette exposition exceptionnelle regroupe plus de quatre-vingts œuvres majeures du mouvement impressionniste."],"female_lines":["",""]},{"point":2,"male_lines":["Les horaires d'ouverture sont de dix heures à dix-sept heures du mardi au dimanche.","L'entrée est gratuite pour les enfants de moins de douze ans accompagnés d'un adulte."],"female_lines":["",""]},{"point":3,"male_lines":["Pour les adultes, le tarif est de vingt-deux dollars, tarif réduit à quinze dollars pour les étudiants et aînés.","Des visites guidées sont offertes tous les jours à onze heures et quatorze heures."],"female_lines":["",""]},{"point":4,"male_lines":["Un audioguide est inclus dans le prix du billet et disponible en français et en anglais.","Le café du musée propose un menu spécial « pause artistique » pendant toute la durée de l'exposition."],"female_lines":["",""]},{"point":5,"male_lines":["L'exposition se termine le quinze mars prochain, ne manquez pas cette occasion unique.","Réservez vos billets en ligne sur mbam point qc point ca pour éviter les files d'attente."],"female_lines":["",""]}]},{"id":14,"section":"C","theme":"Annonce de recrutement","question":"Quel type de contrat est proposé ?","options":[{"id":"A","text":"Un contrat permanent à temps plein","image_prompt":"Permanent full-time job offer with benefits package"},{"id":"B","text":"Un contrat temporaire de six mois","image_prompt":"Six month temporary contract with renewal possibility"},{"id":"C","text":"Un emploi étudiant à temps partiel","image_prompt":"Part-time student job with flexible hours"},{"id":"D","text":"Un stage non rémunéré","image_prompt":"Unpaid internship opportunity for students"}],"correct":0,"transcript_fr":"Point 1 : La Société de transport de Montréal recrute des conducteurs d'autobus pour un emploi permanent. Point 2 : Le poste offre quarante heures par semaine avec des avantages sociaux complets dès le premier jour. Point 3 : Le salaire de départ est de vingt-six dollars de l'heure avec des augmentations programmées. Point 4 : La formation rémunérée dure huit semaines et débute le premier de chaque mois. Point 5 : Les candidats doivent posséder le permis de conduire classe deux valide ou en cours d'obtention. Point 6 : Aucune expérience préalable n'est requise, nous formons tous nos employés. Point 7 : Les avantages incluent un régime de retraite, assurances santé et dentaire, et congés annuels payés. Point 8 : Les quarts de travail rotatifs incluent jour, soir et fin de semaine selon l'ancienneté. Point 9 : Pour postuler, visitez notre site carrieres point stm point info avant le trente du mois. Point 10 : Joignez-vous à une équipe dynamique qui dessert plus de deux millions de déplacements par jour.","transcript_en":"Point 1: The Montreal Transit Corporation is recruiting bus drivers for permanent employment. Point 2: The position offers forty hours per week with full benefits from day one. Point 3: Starting salary is twenty-six dollars per hour with scheduled increases. Point 4: Paid training lasts eight weeks and begins on the first of each month. Point 5: Candidates must possess a valid class two driver's license or be in the process of obtaining one. Point 6: No prior experience is required, we train all our employees. Point 7: Benefits include a pension plan, health and dental insurance, and paid annual vacation. Point 8: Rotating shifts include day, evening and weekend according to seniority. Point 9: To apply, visit our website carrieres dot stm dot info before the thirtieth of the month. Point 10: Join a dynamic team that serves more than two million trips per day.","points":[{"point":1,"male_lines":["La Société de transport de Montréal recrute des conducteurs d'autobus pour un emploi permanent.","Le poste offre quarante heures par semaine avec des avantages sociaux complets dès le premier jour."],"female_lines":["",""]},{"point":2,"male_lines":["Le salaire de départ est de vingt-six dollars de l'heure avec des augmentations programmées.","La formation rémunérée dure huit semaines et débute le premier de chaque mois."],"female_lines":["",""]},{"point":3,"male_lines":["Les candidats doivent posséder le permis de conduire classe deux valide ou en cours d'obtention.","Aucune expérience préalable n'est requise, nous formons tous nos employés."],"female_lines":["",""]},{"point":4,"male_lines":["Les avantages incluent un régime de retraite, assurances santé et dentaire, et congés annuels payés.","Les quarts de travail rotatifs incluent jour, soir et fin de semaine selon l'ancienneté."],"female_lines":["",""]},{"point":5,"male_lines":["Pour postuler, visitez notre site carrieres point stm point info avant le trente du mois.","Joignez-vous à une équipe dynamique qui dessert plus de deux millions de déplacements par jour."],"female_lines":["",""]}]},{"id":15,"section":"C","theme":"Message de service public","question":"Quelle mesure est mise en place pour les collectes ?","options":[{"id":"A","text":"Collecte décalée d'une journée","image_prompt":"Garbage collection delayed by one day notice"},{"id":"B","text":"Collecte avancée d'une journée","image_prompt":"Early garbage pickup schedule change notice"},{"id":"C","text":"Double collecte la semaine prochaine","image_prompt":"Double garbage collection scheduled for next week"},{"id":"D","text":"Collecte suspendue jusqu'à nouvel ordre","image_prompt":"Garbage collection suspended until further notice"}],"correct":0,"transcript_fr":"Point 1 : Avis aux citoyens de l'arrondissement Plateau-Mont-Royal concernant la collecte des déchets. Point 2 : En raison de la fête nationale, la collecte régulière du vingt-quatre juin sera décalée au lendemain. Point 3 : Si votre collecte normale est le lundi, elle aura lieu le mardi vingt-cinq juin. Point 4 : Si votre collecte est le mardi, elle aura lieu le mercredi vingt-six juin. Point 5 : Les horaires de collecte restent inchangés, seule la date change. Point 6 : Les matières recyclables suivent le même décalage que les ordures ménagères. Point 7 : Les compostables seront également ramassés avec un jour de retard. Point 8 : Les écocentres fermeront exceptionnellement le vingt-quatre juin. Point 9 : Nous vous remercions de votre compréhension et de votre collaboration. Point 10 : Pour connaître votre jour de collecte, consultez l'application Montréal en ligne.","transcript_en":"Point 1: Notice to citizens of the Plateau-Mont-Royal borough regarding waste collection. Point 2: Due to the national holiday, regular collection on June twenty-fourth will be postponed to the next day. Point 3: If your normal collection is Monday, it will take place on Tuesday June twenty-fifth. Point 4: If your collection is Tuesday, it will take place on Wednesday June twenty-sixth. Point 5: Collection schedules remain unchanged, only the date changes. Point 6: Recyclables follow the same delay as household waste. Point 7: Compostables will also be collected with one day delay. Point 8: Ecocenters will be exceptionally closed on June twenty-fourth. Point 9: We thank you for your understanding and cooperation. Point 10: To know your collection day, consult the Montreal online application.","points":[{"point":1,"male_lines":["Avis aux citoyens de l'arrondissement Plateau-Mont-Royal concernant la collecte des déchets.","En raison de la fête nationale, la collecte régulière du vingt-quatre juin sera décalée au lendemain."],"female_lines":["",""]},{"point":2,"male_lines":["Si votre collecte normale est le lundi, elle aura lieu le mardi vingt-cinq juin.","Si votre collecte est le mardi, elle aura lieu le mercredi vingt-six juin."],"female_lines":["",""]},{"point":3,"male_lines":["Les horaires de collecte restent inchangés, seule la date change.","Les matières recyclables suivent le même décalage que les ordures ménagères."],"female_lines":["",""]},{"point":4,"male_lines":["Les compostables seront également ramassés avec un jour de retard.","Les écocentres fermeront exceptionnellement le vingt-quatre juin."],"female_lines":["",""]},{"point":5,"male_lines":["Nous vous remercions de votre compréhension et de votre collaboration.","Pour connaître votre jour de collecte, consultez l'application Montréal en ligne."],"female_lines":["",""]}]},{"id":16,"section":"C","theme":"Annonce universitaire","question":"Quelle est la date butoir pour les inscriptions ?","options":[{"id":"A","text":"Le premier mars","image_prompt":"March first deadline calendar with university logo"},{"id":"B","text":"Le quinze mars","image_prompt":"March fifteenth registration deadline notice"},{"id":"C","text":"Le premier avril","image_prompt":"April first enrollment deadline announcement"},{"id":"D","text":"Le trente avril","image_prompt":"April thirtieth final registration date poster"}],"correct":1,"transcript_fr":"Point 1 : L'Université du Québec à Montréal informe les étudiants de la session d'été. Point 2 : Les inscriptions pour les cours de la session d'été deux mille vingt-six sont ouvertes. Point 3 : La date limite pour s'inscrire sans frais de retard est fixée au quinze mars. Point 4 : Après cette date, des frais administratifs de cinquante dollars s'appliqueront. Point 5 : Les cours débuteront le cinq mai et se termineront le quinze août. Point 6 : La période de désinscription sans mention d'échec se termine le vingt mai. Point 7 : Les étudiants internationaux doivent contacter le bureau des admissions avant de s'inscrire. Point 8 : Les bourses d'été sont disponibles, date limite de demande le vingt mars. Point 9 : Les horaires de cours sont consultables sur le portail étudiant étudiant point uqam point ca. Point 10 : Pour toute assistance, le centre d'aide est ouvert du lundi au vendredi de neuf heures à seize heures.","transcript_en":"Point 1: The University of Quebec in Montreal informs students about the summer session. Point 2: Registrations for summer session two thousand twenty-six courses are open. Point 3: The deadline to register without late fees is set for March fifteenth. Point 4: After this date, administrative fees of fifty dollars will apply. Point 5: Classes begin May fifth and end August fifteenth. Point 6: The withdrawal period without failure notation ends May twentieth. Point 7: International students must contact the admissions office before registering. Point 8: Summer scholarships are available, application deadline March twentieth. Point 9: Course schedules are available on the student portal etudiant dot uqam dot ca. Point 10: For any assistance, the help center is open Monday through Friday from nine AM to four PM.","points":[{"point":1,"male_lines":["L'Université du Québec à Montréal informe les étudiants de la session d'été.","Les inscriptions pour les cours de la session d'été deux mille vingt-six sont ouvertes."],"female_lines":["",""]},{"point":2,"male_lines":["La date limite pour s'inscrire sans frais de retard est fixée au quinze mars.","Après cette date, des frais administratifs de cinquante dollars s'appliqueront."],"female_lines":["",""]},{"point":3,"male_lines":["Les cours débuteront le cinq mai et se termineront le quinze août.","La période de désinscription sans mention d'échec se termine le vingt mai."],"female_lines":["",""]},{"point":4,"male_lines":["Les étudiants internationaux doivent contacter le bureau des admissions avant de s'inscrire.","Les bourses d'été sont disponibles, date limite de demande le vingt mars."],"female_lines":["",""]},{"point":5,"male_lines":["Les horaires de cours sont consultables sur le portail étudiant étudiant point uqam point ca.","Pour toute assistance, le centre d'aide est ouvert du lundi au vendredi de neuf heures à seize heures."],"female_lines":["",""]}]},{"id":17,"section":"D","theme":"Intention : Demander un service","question":"Quelle est l'intention principale du client ?","options":[{"id":"A","text":"Il veut se plaindre d'un produit défectueux","image_prompt":"Angry customer complaining about broken product at counter"},{"id":"B","text":"Il souhaite échanger un article","image_prompt":"Customer wanting to exchange clothing item at store"},{"id":"C","text":"Il demande un remboursement","image_prompt":"Customer requesting cash refund at customer service"},{"id":"D","text":"Il veut acheter un article supplémentaire","image_prompt":"Customer wanting to buy additional item at checkout"}],"correct":2,"transcript_fr":"HOMME : Bonjour, je suis venu la semaine dernière acheter ce manteau, mais il ne me convient pas. FEMME : Je vois, qu'est-ce qui ne va pas avec le manteau ? HOMME : La taille est trop grande et la couleur ne correspond pas à ce que je cherchais. FEMME : Avez-vous le ticket de caisse et l'étiquette ? HOMME : Oui, tout est là, je n'ai jamais porté le manteau. FEMME : Très bien, souhaitez-vous l'échanger contre une autre taille ? HOMME : Non, j'ai trouvé ailleurs finalement. Je préfère récupérer mon argent. FEMME : Compris, je procède au remboursement sur votre carte. HOMME : Merci beaucoup pour votre aide.","transcript_en":"MAN: Hello, I came last week to buy this coat, but it doesn't suit me. WOMAN: I see, what's wrong with the coat? MAN: The size is too big and the color doesn't match what I was looking for. WOMAN: Do you have the receipt and the tag? MAN: Yes, everything is here, I never wore the coat. WOMAN: Very well, would you like to exchange it for another size? MAN: No, I found something else elsewhere. I prefer to get my money back. WOMAN: Understood, I'll process the refund on your card. MAN: Thank you very much for your help.","points":[{"point":1,"male_lines":["Bonjour, je suis venu la semaine dernière acheter ce manteau, mais il ne me convient pas.","La taille est trop grande et la couleur ne correspond pas à ce que je cherchais."],"female_lines":["Je vois, qu'est-ce qui ne va pas avec le manteau ?","Avez-vous le ticket de caisse et l'étiquette ?"]},{"point":2,"male_lines":["Oui, tout est là, je n'ai jamais porté le manteau.","Non, j'ai trouvé ailleurs finalement. Je préfère récupérer mon argent."],"female_lines":["Très bien, souhaitez-vous l'échanger contre une autre taille ?","Compris, je procède au remboursement sur votre carte."]}]},{"id":18,"section":"D","theme":"Intention : Donner un conseil","question":"Quelle intention exprime la femme ?","options":[{"id":"A","text":"Elle veut critiquer la décision de son ami","image_prompt":"Woman criticizing friend's decision with disapproving look"},{"id":"B","text":"Elle souhaite encourager son ami à persévérer","image_prompt":"Woman encouraging friend to keep going with supportive gesture"},{"id":"C","text":"Elle donne un conseil pratique","image_prompt":"Woman giving practical advice to friend over coffee"},{"id":"D","text":"Elle refuse d'aider son ami","image_prompt":"Woman refusing to help friend with dismissive gesture"}],"correct":2,"transcript_fr":"HOMME : Je ne sais pas quoi faire, j'ai postulé à dix emplois et aucune réponse positive. FEMME : Écoute, le marché de l'emploi est difficile en ce moment, ne te décourage pas. HOMME : Mais ça fait trois mois déjà, je commence à désespérer. FEMME : As-tu fait relire ton curriculum vitae par un professionnel ? HOMME : Non, je l'ai fait moi-même. FEMME : Je te conseille de contacter le centre d'emploi de ton arrondissement. HOMME : Tu crois que ça peut vraiment aider ? FEMME : Absolument, ils offrent des ateliers gratuits sur la rédaction de CV et la préparation aux entrevues. HOMME : Bonne idée, je vais prendre rendez-vous demain.","transcript_en":"MAN: I don't know what to do, I applied to ten jobs and no positive response. WOMAN: Listen, the job market is difficult right now, don't get discouraged. MAN: But it's been three months already, I'm starting to despair. WOMAN: Have you had your curriculum vitae reviewed by a professional? MAN: No, I did it myself. WOMAN: I advise you to contact the employment center in your borough. MAN: Do you think it can really help? WOMAN: Absolutely, they offer free workshops on CV writing and interview preparation. MAN: Good idea, I'll make an appointment tomorrow.","points":[{"point":1,"male_lines":["Je ne sais pas quoi faire, j'ai postulé à dix emplois et aucune réponse positive.","Mais ça fait trois mois déjà, je commence à désespérer."],"female_lines":["Écoute, le marché de l'emploi est difficile en ce moment, ne te décourage pas.","As-tu fait relire ton curriculum vitae par un professionnel ?"]},{"point":2,"male_lines":["Non, je l'ai fait moi-même.","Tu crois que ça peut vraiment aider ?"],"female_lines":["Je te conseille de contacter le centre d'emploi de ton arrondissement.","Absolument, ils offrent des ateliers gratuits sur la rédaction de CV et la préparation aux entrevues."]}]},{"id":19,"section":"D","theme":"Intention : Exprimer une désaccord","question":"Quelle est l'intention de l'homme ?","options":[{"id":"A","text":"Il veut imposer sa décision","image_prompt":"Man imposing his decision with authoritarian gesture"},{"id":"B","text":"Il exprime un désaccord poli","image_prompt":"Man politely disagreeing during conversation"},{"id":"C","text":"Il cherche à convaincre par la flatterie","image_prompt":"Man trying to convince through flattery and compliments"},{"id":"D","text":"Il accepte finalement l'idée de sa collègue","image_prompt":"Man finally accepting colleague's idea with nod"}],"correct":1,"transcript_fr":"FEMME : Je pense que nous devrions investir dans une nouvelle campagne publicitaire immédiatement. HOMME : Je comprends ton point de vue, mais je ne suis pas tout à fait d'accord avec cette approche. FEMME : Pourquoi ? Notre concurrent vient de lancer une grande offensive marketing. HOMME : C'est vrai, mais notre budget est limité ce trimestre. FEMME : Alors tu proposes quoi ? Attendre encore ? HOMME : Je suggérons plutôt de renforcer d'abord notre présence sur les réseaux sociaux. FEMME : Ce n'est pas assez visible comme stratégie. HOMME : Je respecte ton opinion, mais je crois sincèrement que c'est plus sage financièrement. FEMME : D'accord, discutons-en avec l'équipe demain.","transcript_en":"WOMAN: I think we should invest in a new advertising campaign immediately. MAN: I understand your point of view, but I don't quite agree with this approach. WOMAN: Why? Our competitor just launched a major marketing offensive. MAN: That's true, but our budget is limited this quarter. WOMAN: So what do you propose? Wait longer? MAN: I suggest we first strengthen our presence on social media instead. WOMAN: That's not visible enough as a strategy. MAN: I respect your opinion, but I sincerely believe it's more financially wise. WOMAN: Okay, let's discuss it with the team tomorrow.","points":[{"point":1,"male_lines":["Je comprends ton point de vue, mais je ne suis pas tout à fait d'accord avec cette approche.","C'est vrai, mais notre budget est limité ce trimestre."],"female_lines":["Je pense que nous devrions investir dans une nouvelle campagne publicitaire immédiatement.","Pourquoi ? Notre concurrent vient de lancer une grande offensive marketing."]},{"point":2,"male_lines":["Je suggérons plutôt de renforcer d'abord notre présence sur les réseaux sociaux.","Je respecte ton opinion, mais je crois sincèrement que c'est plus sage financièrement."],"female_lines":["Alors tu proposes quoi ? Attendre encore ?","Ce n'est pas assez visible comme stratégie."]}]},{"id":20,"section":"D","theme":"Intention : S'excuser","question":"Quelle intention exprime la femme ?","options":[{"id":"A","text":"Elle veut se justifier","image_prompt":"Woman justifying herself with defensive posture"},{"id":"B","text":"Elle présente des excuses sincères","image_prompt":"Woman offering sincere apologies with remorseful expression"},{"id":"C","text":"Elle minimise son erreur","image_prompt":"Woman minimizing her mistake with dismissive gesture"},{"id":"D","text":"Elle blame quelqu'un d'autre","image_prompt":"Woman blaming someone else with pointing finger"}],"correct":1,"transcript_fr":"HOMME : Madame, vous étiez censée me remettre le rapport hier, et je ne l'ai toujours pas reçu. FEMME : Monsieur, je suis vraiment désolée, c'est entièrement de ma faute. HOMME : Cela met tout notre projet en retard, vous réalisez ? FEMME : Je comprends parfaitement, et je m'excuse sincèrement de ce contretemps. HOMME : J'espère que cela ne se reproduira pas. FEMME : Je vous assure que j'ai priorisé votre dossier ce matin. HOMME : Quand puis-je l'avoir exactement ? FEMME : Le document sera sur votre bureau avant quatorze heures aujourd'hui, c'est promis. HOMME : Très bien, je compte sur vous.","transcript_en":"MAN: Ma'am, you were supposed to give me the report yesterday, and I still haven't received it. WOMAN: Sir, I'm really sorry, it's entirely my fault. MAN: This puts our whole project behind schedule, do you realize? WOMAN: I understand perfectly, and I sincerely apologize for this delay. MAN: I hope this won't happen again. WOMAN: I assure you that I prioritized your file this morning. MAN: When can I have it exactly? WOMAN: The document will be on your desk before two PM today, I promise. MAN: Very well, I'm counting on you.","points":[{"point":1,"male_lines":["Madame, vous étiez censée me remettre le rapport hier, et je ne l'ai toujours pas reçu.","Cela met tout notre projet en retard, vous réalisez ?"],"female_lines":["Monsieur, je suis vraiment désolée, c'est entièrement de ma faute.","Je comprends parfaitement, et je m'excuse sincèrement de ce contretemps."]},{"point":2,"male_lines":["J'espère que cela ne se reproduira pas.","Quand puis-je l'avoir exactement ?"],"female_lines":["Je vous assure que j'ai priorisé votre dossier ce matin.","Le document sera sur votre bureau avant quatorze heures aujourd'hui, c'est promis."]}]},{"id":21,"section":"D","theme":"Intention : Faire une suggestion","question":"Quelle est l'intention de l'homme ?","options":[{"id":"A","text":"Il ordonne à sa femme de faire quelque chose","image_prompt":"Man ordering his wife with commanding tone"},{"id":"B","text":"Il fait une suggestion pour le week-end","image_prompt":"Man making weekend suggestion with hopeful expression"},{"id":"C","text":"Il se plaint de la routine","image_prompt":"Man complaining about routine with frustrated face"},{"id":"D","text":"Il demande la permission de sortir seul","image_prompt":"Man asking permission to go out alone"}],"correct":1,"transcript_fr":"FEMME : Chéri, nous faisons toujours la même chose le samedi, c'est monotone. HOMME : Tu as raison, on devrait changer nos habitudes. FEMME : Qu'est-ce que tu proposes ? HOMME : Et si on allait visiter le jardin botanique ce week-end ? FEMME : Le jardin botanique ? Je n'y ai pas mis les pieds depuis des années. HOMME : Ils ont une nouvelle exposition sur les orchidées tropicales en ce moment. FEMME : Ça pourrait être intéressant, mais il risque de pleuvoir. HOMME : On peut prendre le métro, c'est direct jusqu'à la station Pie-IX. FEMME : Bonne idée, réservons nos billets en ligne ce soir.","transcript_en":"WOMAN: Honey, we always do the same thing on Saturday, it's monotonous. MAN: You're right, we should change our habits. WOMAN: What do you suggest? MAN: What if we visited the botanical garden this weekend? WOMAN: The botanical garden? I haven't set foot there in years. MAN: They have a new exhibition on tropical orchids right now. WOMAN: That could be interesting, but it might rain. MAN: We can take the metro, it's direct to Pie-IX station. WOMAN: Good idea, let's book our tickets online tonight.","points":[{"point":1,"male_lines":["Tu as raison, on devrait changer nos habitudes.","Et si on allait visiter le jardin botanique ce week-end ?"],"female_lines":["Chéri, nous faisons toujours la même chose le samedi, c'est monotone.","Qu'est-ce que tu proposes ?"]},{"point":2,"male_lines":["Ils ont une nouvelle exposition sur les orchidées tropicales en ce moment.","On peut prendre le métro, c'est direct jusqu'à la station Pie-IX."],"female_lines":["Le jardin botanique ? Je n'y ai pas mis les pieds depuis des années.","Ça pourrait être intéressant, mais il risque de pleuvoir."]}]},{"id":22,"section":"D","theme":"Intention : Refuser poliment","question":"Quelle intention exprime la femme ?","options":[{"id":"A","text":"Elle accepte avec enthousiasme","image_prompt":"Woman accepting enthusiastically with big smile"},{"id":"B","text":"Elle refuse poliment une invitation","image_prompt":"Woman politely declining invitation with regretful smile"},{"id":"C","text":"Elle reporte la décision à plus tard","image_prompt":"Woman postponing decision with uncertain gesture"},{"id":"D","text":"Elle exprime de la colère","image_prompt":"Woman expressing anger with upset expression"}],"correct":1,"transcript_fr":"HOMME : Sophie, nous organisons une soirée chez moi vendredi, tu viens ? FEMME : C'est gentil de m'inviter, mais je ne pourrai pas malheureusement. HOMME : Oh, tu as déjà des projets ? FEMME : Oui, mes parents arrivent de Québec pour le weekend, je dois les accueillir. HOMME : Je comprends, c'est important la famille. FEMME : Absolument, et je ne les vois que quelques fois par année. HOMME : On remettra ça à une autre occasion alors. FEMME : Volontiers, propose-moi une date en début de semaine prochaine. HOMME : Parfait, je te tiens au courant.","transcript_en":"MAN: Sophie, we're organizing an evening at my place Friday, are you coming? WOMAN: It's kind of you to invite me, but I can't unfortunately. MAN: Oh, do you already have plans? WOMAN: Yes, my parents are arriving from Quebec for the weekend, I have to welcome them. MAN: I understand, family is important. WOMAN: Absolutely, and I only see them a few times per year. MAN: We'll postpone it to another occasion then. WOMAN: Gladly, suggest a date early next week. MAN: Perfect, I'll keep you posted.","points":[{"point":1,"male_lines":["Sophie, nous organisons une soirée chez moi vendredi, tu viens ?","Oh, tu as déjà des projets ?"],"female_lines":["C'est gentil de m'inviter, mais je ne pourrai pas malheureusement.","Oui, mes parents arrivent de Québec pour le weekend, je dois les accueillir."]},{"point":2,"male_lines":["Je comprends, c'est important la famille.","On remettra ça à une autre occasion alors."],"female_lines":["Absolument, et je ne les vois que quelques fois par année.","Volontiers, propose-moi une date en début de semaine prochaine."]}]},{"id":23,"section":"E","theme":"Entrevue : Environnement","question":"Selon l'experte, quelle est la principale menace pour les glaciers ?","options":[{"id":"A","text":"La pollution plastique des océans","image_prompt":"Ocean plastic pollution affecting glaciers"},{"id":"B","text":"Le réchauffement climatique","image_prompt":"Global warming melting glacier ice"},{"id":"C","text":"La déforestation massive","image_prompt":"Massive deforestation near glacier regions"},{"id":"D","text":"L'urbanisation des zones polaires","image_prompt":"Urbanization in polar regions near glaciers"}],"correct":1,"transcript_fr":"JOURNALISTE : Docteur Lefebvre, vous étudiez les glaciers depuis vingt ans. Quel est leur état actuel ? EXPERTE : La situation est alarmante. Nous perdons environ trois cent trente milliards de tonnes de glace par année. JOURNALISTE : Quelle est la cause principale selon vos recherches ? EXPERTE : Sans aucun doute, le réchauffement climatique d'origine anthropique. JOURNALISTE : Pouvez-vous expliquer les conséquences concrètes ? EXPERTE : La montée des océans menace quatre cent millions de personnes vivant en zone côtière. JOURNALISTE : Existe-t-il des solutions pour ralentir ce phénomène ? EXPERTE : Nous devons réduire nos émissions de carbone de quarante-cinq pour cent d'ici deux mille trente. JOURNALISTE : Le Canada est-il particulièrement concerné ? EXPERTE : Absolument, l'Arctique canadien se réchauffe trois fois plus vite que la moyenne mondiale.","transcript_en":"JOURNALIST: Dr. Lefebvre, you have been studying glaciers for twenty years. What is their current state? EXPERT: The situation is alarming. We are losing about three hundred thirty billion tons of ice per year. JOURNALIST: What is the main cause according to your research? EXPERT: Without a doubt, anthropogenic climate warming. JOURNALIST: Can you explain the concrete consequences? EXPERT: Rising oceans threaten four hundred million people living in coastal zones. JOURNALIST: Are there solutions to slow down this phenomenon? EXPERT: We must reduce our carbon emissions by forty-five percent by two thousand thirty. JOURNALIST: Is Canada particularly concerned? EXPERT: Absolutely, the Canadian Arctic is warming three times faster than the global average.","points":[{"point":1,"male_lines":["Docteur Lefebvre, vous étudiez les glaciers depuis vingt ans. Quel est leur état actuel ?","Quelle est la cause principale selon vos recherches ?"],"female_lines":["La situation est alarmante. Nous perdons environ trois cent trente milliards de tonnes de glace par année.","Sans aucun doute, le réchauffement climatique d'origine anthropique."]},{"point":2,"male_lines":["Pouvez-vous expliquer les conséquences concrètes ?","Existe-t-il des solutions pour ralentir ce phénomène ?"],"female_lines":["La montée des océans menace quatre cent millions de personnes vivant en zone côtière.","Nous devons réduire nos émissions de carbone de quarante-cinq pour cent d'ici deux mille trente."]}]},{"id":24,"section":"E","theme":"Entrevue : Économie locale","question":"Quel conseil donne l'expert aux commerçants ?","options":[{"id":"A","text":"Baisser leurs prix de cinquante pour cent","image_prompt":"Store with fifty percent off sale signs everywhere"},{"id":"B","text":"Développer leur présence en ligne","image_prompt":"Local business developing online presence with website"},{"id":"C","text":"Déménager en banlieue","image_prompt":"Business relocating to suburban shopping center"},{"id":"D","text":"Embaucher plus de personnel","image_prompt":"Local shop hiring more staff with help wanted sign"}],"correct":1,"transcript_fr":"JOURNALISTE : Monsieur Gagnon, les petits commerces du centre-ville ferment les uns après les autres. Pourquoi ? EXPERT : Les habitudes de consommation ont radicalement changé avec la pandémie. JOURNALISTE : Quels sont les défis spécifiques des commerçants québécois ? EXPERT : Ils doivent rivaliser avec les géants du commerce en ligne tout en payant des loyers élevés. JOURNALISTE : Quelle stratégie recommandez-vous pour survivre ? EXPERT : Il est crucial de développer une présence numérique forte et un service personnalisé. JOURNALISTE : Les consommateurs peuvent-ils aider ? EXPERT : Absolument, en choisissant consciemment d'acheter local même si c'est légèrement plus cher. JOURNALISTE : L'avenir est-il sombre pour le commerce de proximité ? EXPERT : Pas nécessairement, ceux qui s'adaptent créent une expérience client unique qui attire la clientèle.","transcript_en":"JOURNALIST: Mr. Gagnon, small downtown businesses are closing one after another. Why? EXPERT: Consumer habits have radically changed with the pandemic. JOURNALIST: What are the specific challenges for Quebec merchants? EXPERT: They must compete with online commerce giants while paying high rents. JOURNALIST: What strategy do you recommend to survive? EXPERT: It is crucial to develop a strong digital presence and personalized service. JOURNALIST: Can consumers help? EXPERT: Absolutely, by consciously choosing to buy local even if it's slightly more expensive. JOURNALIST: Is the future dark for neighborhood commerce? EXPERT: Not necessarily, those who adapt create a unique customer experience that attracts clientele.","points":[{"point":1,"male_lines":["Monsieur Gagnon, les petits commerces du centre-ville ferment les uns après les autres. Pourquoi ?","Quels sont les défis spécifiques des commerçants québécois ?"],"female_lines":["Les habitudes de consommation ont radicalement changé avec la pandémie.","Ils doivent rivaliser avec les géants du commerce en ligne tout en payant des loyers élevés."]},{"point":2,"male_lines":["Quelle stratégie recommandez-vous pour survivre ?","Les consommateurs peuvent-ils aider ?"],"female_lines":["Il est crucial de développer une présence numérique forte et un service personnalisé.","Absolument, en choisissant consciemment d'acheter local même si c'est légèrement plus cher."]}]},{"id":25,"section":"E","theme":"Entrevue : Santé publique","question":"Quel est le principal message de la médecin ?","options":[{"id":"A","text":"Éviter complètement les médicaments","image_prompt":"Doctor advising to avoid all medications completely"},{"id":"B","text":"Consulter avant d'arrêter un traitement","image_prompt":"Patient consulting doctor before stopping medication"},{"id":"C","text":"Augmenter les doses prescrites","image_prompt":"Patient increasing medication dosage against advice"},{"id":"D","text":"Partager ses médicaments avec la famille","image_prompt":"Family sharing prescription medications between members"}],"correct":1,"transcript_fr":"JOURNALISTE : Dre. Martin, vous constatez une augmentation de l'automédication. Quels en sont les dangers ? MÉDECIN : Les patients arrêtent souvent leurs traitements chroniques sans avis médical. JOURNALISTE : Quels risques cela comporte-t-il concrètement ? MÉDECIN : Pour l'hypertension ou le diabète, cela peut provoquer des complications graves voire mortelles. JOURNALISTE : Que conseillez-vous aux auditeurs qui prennent des médicaments ? MÉDECIN : Il est essentiel de consulter son médecin avant toute modification de traitement. JOURNALISTE : Et concernant les antibiotiques ? MÉDECIN : Jamais sans prescription, cela contribue à la résistance bactérienne mondiale. JOURNALISTE : Comment améliorer l'éducation thérapeutique ? MÉDECIN : Les pharmaciens et médecins doivent prendre plus de temps pour expliquer les traitements.","transcript_en":"JOURNALIST: Dr. Martin, you are noticing an increase in self-medication. What are the dangers? DOCTOR: Patients often stop their chronic treatments without medical advice. JOURNALIST: What risks does this concretely entail? DOCTOR: For hypertension or diabetes, this can cause serious or even fatal complications. JOURNALIST: What do you advise listeners who take medications? DOCTOR: It is essential to consult your doctor before any treatment modification. JOURNALIST: And regarding antibiotics? DOCTOR: Never without prescription, this contributes to global bacterial resistance. JOURNALIST: How to improve therapeutic education? DOCTOR: Pharmacists and doctors must take more time to explain treatments.","points":[{"point":1,"male_lines":["Dre. Martin, vous constatez une augmentation de l'automédication. Quels en sont les dangers ?","Quels risques cela comporte-t-il concrètement ?"],"female_lines":["Les patients arrêtent souvent leurs traitements chroniques sans avis médical.","Pour l'hypertension ou le diabète, cela peut provoquer des complications graves voire mortelles."]},{"point":2,"male_lines":["Que conseillez-vous aux auditeurs qui prennent des médicaments ?","Et concernant les antibiotiques ?"],"female_lines":["Il est essentiel de consulter son médecin avant toute modification de traitement.","Jamais sans prescription, cela contribue à la résistance bactérienne mondiale."]}]},{"id":26,"section":"E","theme":"Entrevue : Technologie","question":"Quelle est la préoccupation principale de l'ingénieur ?","options":[{"id":"A","text":"Le coût trop élevé des ordinateurs","image_prompt":"Expensive computers with high price tags"},{"id":"B","text":"La protection de la vie privée","image_prompt":"Privacy protection with data security shield"},{"id":"C","text":"La lenteur des connexions internet","image_prompt":"Slow internet connection loading screen"},{"id":"D","text":"Le manque de formation technique","image_prompt":"Lack of technical training in schools"}],"correct":1,"transcript_fr":"JOURNALISTE : Madame Chen, en tant qu'experte en cybersécurité, quelle est la plus grande menace actuelle ? INGÉNIEURE : Ce n'est pas technique, c'est la collecte massive de données personnelles par les grandes entreprises. JOURNALISTE : Les consommateurs sont-ils conscients de ces risques ? INGÉNIEURE : Malheureusement non, ils acceptent les conditions d'utilisation sans les lire. JOURNALISTE : Quelles sont les conséquences possibles ? INGÉNIEURE : Des profils détaillés sont vendus à des fins publicitaires ou politiques sans consentement éclairé. JOURNALISTE : Que peut-on faire pour se protéger ? INGÉNIEURE : Utiliser des mots de passe complexes, l'authentification à deux facteurs et limiter les informations partagées. JOURNALISTE : Le gouvernement canadien intervient-il ? INGÉNIEURE : La loi vingt-cinq sur la protection des renseignements personnels est une avancée, mais insuffisante.","transcript_en":"JOURNALIST: Ms. Chen, as a cybersecurity expert, what is the greatest current threat? ENGINEER: It's not technical, it's the massive collection of personal data by large companies. JOURNALIST: Are consumers aware of these risks? ENGINEER: Unfortunately no, they accept terms of use without reading them. JOURNALIST: What are the possible consequences? ENGINEER: Detailed profiles are sold for advertising or political purposes without informed consent. JOURNALIST: What can we do to protect ourselves? ENGINEER: Use complex passwords, two-factor authentication and limit shared information. JOURNALIST: Is the Canadian government intervening? ENGINEER: Law twenty-five on personal information protection is progress, but insufficient.","points":[{"point":1,"male_lines":["Madame Chen, en tant qu'experte en cybersécurité, quelle est la plus grande menace actuelle ?","Les consommateurs sont-ils conscients de ces risques ?"],"female_lines":["Ce n'est pas technique, c'est la collecte massive de données personnelles par les grandes entreprises.","Malheureusement non, ils acceptent les conditions d'utilisation sans les lire."]},{"point":2,"male_lines":["Quelles sont les conséquences possibles ?","Que peut-on faire pour se protéger ?"],"female_lines":["Des profils détaillés sont vendus à des fins publicitaires ou politiques sans consentement éclairé.","Utiliser des mots de passe complexes, l'authentification à deux facteurs et limiter les informations partagées."]}]},{"id":27,"section":"F","theme":"Discussion : Télétravail","question":"Quelle est l'opinion de la femme sur le télétravail ?","options":[{"id":"A","text":"Elle le trouve totalement inefficace","image_prompt":"Woman finding remote work completely inefficient"},{"id":"B","text":"Elle pense qu'il devrait être limité à deux jours","image_prompt":"Woman suggesting two-day remote work limit"},{"id":"C","text":"Elle souhaite le rendre permanent","image_prompt":"Woman wanting permanent remote work arrangement"},{"id":"D","text":"Elle est indifférente à cette question","image_prompt":"Woman indifferent to remote work discussion"}],"correct":1,"transcript_fr":"HOMME : Le télétravail a changé notre façon de travailler. Qu'en penses-tu ? FEMME : C'est pratique, mais je trouve qu'on perd le contact humain essentiel. HOMME : Pourtant, les études montrent une productivité accrue à la maison. FEMME : Productive oui, mais créative ? Les idées naissent souvent des discussions informelles. HOMME : Tu préfères retourner au bureau cinq jours par semaine ? FEMME : Non, un équilibre serait idéal. Deux jours de télétravail, trois au bureau. HOMME : C'est ce que propose notre direction pour l'année prochaine. FEMME : Parfait, cela permet de garder la flexibilité sans sacrifier la collaboration.","transcript_en":"MAN: Remote work has changed our way of working. What do you think? WOMAN: It's practical, but I think we lose essential human contact. MAN: Yet studies show increased productivity at home. WOMAN: Productive yes, but creative? Ideas often come from informal discussions. MAN: Do you prefer going back to the office five days a week? WOMAN: No, a balance would be ideal. Two days remote, three at the office. MAN: That's what our management is proposing for next year. WOMAN: Perfect, this allows keeping flexibility without sacrificing collaboration.","points":[{"point":1,"male_lines":["Le télétravail a changé notre façon de travailler. Qu'en penses-tu ?","Pourtant, les études montrent une productivité accrue à la maison."],"female_lines":["C'est pratique, mais je trouve qu'on perd le contact humain essentiel.","Productive oui, mais créative ? Les idées naissent souvent des discussions informelles."]},{"point":2,"male_lines":["Tu préfères retourner au bureau cinq jours par semaine ?","C'est ce que propose notre direction pour l'année prochaine."],"female_lines":["Non, un équilibre serait idéal. Deux jours de télétravail, trois au bureau.","Parfait, cela permet de garder la flexibilité sans sacrifier la collaboration."]}]},{"id":28,"section":"F","theme":"Discussion : Alimentation bio","question":"Pourquoi l'homme achète-t-il des produits biologiques ?","options":[{"id":"A","text":"Parce qu'ils sont moins chers","image_prompt":"Organic products with lower price tags"},{"id":"B","text":"Pour des raisons de santé et d'environnement","image_prompt":"Organic food for health and environment reasons"},{"id":"C","text":"Parce qu'ils sont plus faciles à trouver","image_prompt":"Organic products easily available in supermarket"},{"id":"D","text":"Pour suivre la mode actuelle","image_prompt":"Following organic food trend with fashionable shoppers"}],"correct":1,"transcript_fr":"FEMME : Tu fais toujours tes courses au marché bio ? Ça coûte une fortune ! HOMME : Oui, mais je ne regrette pas cet investissement pour ma santé. FEMME : Penses-tu vraiment que c'est si différent des produits conventionnels ? HOMME : Absolument, moins de pesticides pour moi et moins de pollution des sols. FEMME : Les études scientifiques ne prouvent pas tous ces bienfaits pourtant. HOMME : Même sans preuve absolue, je préfère limiter les risques pour mes enfants. FEMME : Je comprends, mais mon budget ne me permet pas ce choix. HOMME : On peut commencer par les fruits et légumes les plus contaminés, c'est déjà ça.","transcript_en":"WOMAN: You still shop at the organic market? It costs a fortune! MAN: Yes, but I don't regret this investment for my health. WOMAN: Do you really think it's that different from conventional products? MAN: Absolutely, less pesticides for me and less soil pollution. WOMAN: Scientific studies don't prove all these benefits though. MAN: Even without absolute proof, I prefer to limit risks for my children. WOMAN: I understand, but my budget doesn't allow me this choice. MAN: We can start with the most contaminated fruits and vegetables, that's already something.","points":[{"point":1,"male_lines":["Oui, mais je ne regrette pas cet investissement pour ma santé.","Absolument, moins de pesticides pour moi et moins de pollution des sols."],"female_lines":["Tu fais toujours tes courses au marché bio ? Ça coûte une fortune !","Penses-tu vraiment que c'est si différent des produits conventionnels ?"]},{"point":2,"male_lines":["Même sans preuve absolue, je préfère limiter les risques pour mes enfants.","On peut commencer par les fruits et légumes les plus contaminés, c'est déjà ça."],"female_lines":["Les études scientifiques ne prouvent pas tous ces bienfaits pourtant.","Je comprends, mais mon budget ne me permet pas ce choix."]}]},{"id":29,"section":"F","theme":"Discussion : Transport en commun","question":"Quelle solution propose la femme ?","options":[{"id":"A","text":"Acheter une voiture électrique","image_prompt":"Buying electric car as solution to transit issues"},{"id":"B","text":"Augmenter la fréquence des bus","image_prompt":"Increasing bus frequency with more buses on route"},{"id":"C","text":"Améliorer les pistes cyclables","image_prompt":"Improving bike lanes with protected cycling paths"},{"id":"D","text":"Construire une nouvelle ligne de métro","image_prompt":"Building new metro line with construction site"}],"correct":2,"transcript_fr":"HOMME : Le métro est bondé aux heures de pointe, c'est insupportable. FEMME : C'est vrai, mais augmenter la fréquence coûte des millions. HOMME : Alors quelle alternative proposons-nous aux citoyens ? FEMME : Pourquoi ne pas investir massivement dans les infrastructures cyclables ? HOMME : Au Québec ? Avec nos hivers de moins vingt degrés ? FEMME : C'est un mythe, Copenhague et Amsterdam ont les mêmes hivers et tout le monde y roule. HOMME : Tu suggères de remplacer le métro par des vélos ? FEMME : Non, mais compléter le réseau. Les trajets de moins de cinq kilomètres sont parfaits à vélo.","transcript_en":"MAN: The metro is packed during rush hour, it's unbearable. WOMAN: That's true, but increasing frequency costs millions. MAN: So what alternative do we propose to citizens? WOMAN: Why not invest massively in cycling infrastructure? MAN: In Quebec? With our minus twenty degree winters? WOMAN: That's a myth, Copenhagen and Amsterdam have the same winters and everyone rides there. MAN: You suggest replacing the metro with bikes? WOMAN: No, but complementing the network. Trips under five kilometers are perfect by bike.","points":[{"point":1,"male_lines":["Le métro est bondé aux heures de pointe, c'est insupportable.","Alors quelle alternative proposons-nous aux citoyens ?"],"female_lines":["C'est vrai, mais augmenter la fréquence coûte des millions.","Pourquoi ne pas investir massivement dans les infrastructures cyclables ?"]},{"point":2,"male_lines":["Au Québec ? Avec nos hivers de moins vingt degrés ?","Tu suggères de remplacer le métro par des vélos ?"],"female_lines":["C'est un mythe, Copenhague et Amsterdam ont les mêmes hivers et tout le monde y roule.","Non, mais compléter le réseau. Les trajets de moins de cinq kilomètres sont parfaits à vélo."]}]},{"id":30,"section":"F","theme":"Discussion : Éducation des enfants","question":"Sur quoi les deux parents ne sont-ils pas d'accord ?","options":[{"id":"A","text":"Sur l'importance des devoirs","image_prompt":"Parents disagreeing on homework importance"},{"id":"B","text":"Sur l'utilisation des écrans","image_prompt":"Parents arguing about children's screen time"},{"id":"C","text":"Sur les activités parascolaires","image_prompt":"Parents debating extracurricular activities"},{"id":"D","text":"Sur l'heure du coucher","image_prompt":"Parents disagreeing on children's bedtime"}],"correct":1,"transcript_fr":"FEMME : Notre fils passe trois heures par jour sur sa tablette, c'est excessif. HOMME : Il fait ses devoirs, ses résultats sont bons, où est le problème ? FEMME : Le problème est son développement social et physique. Il ne joue plus dehors. HOMME : Les jeux éducatifs stimulent son intelligence, c'est prouvé scientifiquement. FEMME : À huit ans, il a besoin de contact humain réel, pas virtuel. HOMME : D'accord, mais interdire totalement les écrans le marginaliserait à l'école. FEMME : Je ne dis pas interdire, mais limiter à trente minutes par jour. HOMME : C'est irréaliste, compromettons-nous sur une heure.","transcript_en":"WOMAN: Our son spends three hours per day on his tablet, it's excessive. MAN: He does his homework, his grades are good, where's the problem? WOMAN: The problem is his social and physical development. He doesn't play outside anymore. MAN: Educational games stimulate his intelligence, it's scientifically proven. WOMAN: At eight years old, he needs real human contact, not virtual. MAN: Okay, but totally banning screens would marginalize him at school. WOMAN: I'm not saying ban, but limit to thirty minutes per day. MAN: That's unrealistic, let's compromise on one hour.","points":[{"point":1,"male_lines":["Il fait ses devoirs, ses résultats sont bons, où est le problème ?","Les jeux éducatifs stimulent son intelligence, c'est prouvé scientifiquement."],"female_lines":["Notre fils passe trois heures par jour sur sa tablette, c'est excessif.","Le problème est son développement social et physique. Il ne joue plus dehors."]},{"point":2,"male_lines":["D'accord, mais interdire totalement les écrans le marginaliserait à l'école.","C'est irréaliste, compromettons-nous sur une heure."],"female_lines":["À huit ans, il a besoin de contact humain réel, pas virtuel.","Je ne dis pas interdire, mais limiter à trente minutes par jour."]}]},{"id":31,"section":"G","theme":"Conférence : Intelligence artificielle","question":"Quelle est la crainte principale exprimée par le conférencier ?","options":[{"id":"A","text":"Que les robots remplacent tous les emplois artistiques","image_prompt":"AI robots replacing human artists in studio"},{"id":"B","text":"Que l'IA reproduise les biais humains","image_prompt":"AI reproducing human biases in decision making"},{"id":"C","text":"Que les ordinateurs deviennent trop chers","image_prompt":"Expensive computers becoming unaffordable"},{"id":"D","text":"Que l'internet cesse de fonctionner","image_prompt":"Internet shutdown with error messages"}],"correct":1,"transcript_fr":"Point 1 : Bonjour à tous, aujourd'hui nous explorons l'éthique de l'intelligence artificielle. Point 2 : L'IA transforme notre société plus vite que toute technologie précédente. Point 3 : Cependant, ces systèmes apprennent à partir de données humaines souvent biaisées. Point 4 : Par exemple, un algorithme de recrutement a favorisé les candidats masculins car les données historiques étaient sexistes. Point 5 : Ces biais algorithmiques perpétuent les discriminations existantes à grande échelle. Point 6 : Nous devons donc auditer rigoureusement les jeux de données d'entraînement. Point 7 : La diversité dans les équipes de développement est également cruciale. Point 8 : Les gouvernements doivent établir des cadres réglementaires clairs. Point 9 : La transparence des algorithmes publics devrait être obligatoire. Point 10 : Ensemble, nous pouvons diriger l'IA vers un avenir équitable et bénéfique pour tous.","transcript_en":"Point 1: Hello everyone, today we explore the ethics of artificial intelligence. Point 2: AI is transforming our society faster than any previous technology. Point 3: However, these systems learn from human data that is often biased. Point 4: For example, a recruitment algorithm favored male candidates because historical data was sexist. Point 5: These algorithmic biases perpetuate existing discrimination on a large scale. Point 6: We must therefore rigorously audit training datasets. Point 7: Diversity in development teams is also crucial. Point 8: Governments must establish clear regulatory frameworks. Point 9: Transparency of public algorithms should be mandatory. Point 10: Together, we can steer AI toward an equitable and beneficial future for all.","points":[{"point":1,"male_lines":["Bonjour à tous, aujourd'hui nous explorons l'éthique de l'intelligence artificielle.","L'IA transforme notre société plus vite que toute technologie précédente."],"female_lines":["",""]},{"point":2,"male_lines":["Cependant, ces systèmes apprennent à partir de données humaines souvent biaisées.","Par exemple, un algorithme de recrutement a favorisé les candidats masculins car les données historiques étaient sexistes."],"female_lines":["",""]},{"point":3,"male_lines":["Ces biais algorithmiques perpétuent les discriminations existantes à grande échelle.","Nous devons donc auditer rigoureusement les jeux de données d'entraînement."],"female_lines":["",""]},{"point":4,"male_lines":["La diversité dans les équipes de développement est également cruciale.","Les gouvernements doivent établir des cadres réglementaires clairs."],"female_lines":["",""]},{"point":5,"male_lines":["La transparence des algorithmes publics devrait être obligatoire.","Ensemble, nous pouvons diriger l'IA vers un avenir équitable et bénéfique pour tous."],"female_lines":["",""]}]},{"id":32,"section":"G","theme":"Débat : Réforme électorale","question":"Quel système électoral défend l'oratrice ?","options":[{"id":"A","text":"Le scrutin proportionnel pur","image_prompt":"Pure proportional representation voting system"},{"id":"B","text":"Le scrutin majoritaire uninominal","image_prompt":"First-past-the-post voting system ballot"},{"id":"C","text":"Le scrutin proportionnel mixte compensatoire","image_prompt":"Mixed member proportional representation system"},{"id":"D","text":"Le vote obligatoire pour tous","image_prompt":"Mandatory voting for all citizens"}],"correct":2,"transcript_fr":"Point 1 : Mesdames et messieurs, notre système électoral actuel est démocratiquement défectueux. Point 2 : Le scrutin uninominal majoritaire crée des distorsions flagrantes entre les votes et les sièges. Point 3 : En deux mille dix-huit, un parti a obtenu dix pour cent des votes mais zéro député. Point 4 : C'est pourquoi je propose l'adoption du scrutin proportionnel mixte compensatoire. Point 5 : Ce système préserve la représentation locale tout en assurant la proportionnalité. Point 6 : Chaque électeur vote deux fois : pour un candidat local et pour un parti. Point 7 : Les sièges compensatoires équilibrent la représentation selon les votes populaires. Point 8 : L'Allemagne et la Nouvelle-Zélande utilisent ce système avec succès depuis des décennies. Point 9 : Cette réforme renforcerait la légitimité de notre démocratie parlementaire. Point 10 : Je demande au gouvernement de tenir un référendum sur cette question vitale.","transcript_en":"Point 1: Ladies and gentlemen, our current electoral system is democratically defective. Point 2: The first-past-the-post system creates blatant distortions between votes and seats. Point 3: In two thousand eighteen, a party obtained ten percent of votes but zero MPs. Point 4: That is why I propose adopting the mixed member proportional representation system. Point 5: This system preserves local representation while ensuring proportionality. Point 6: Each voter votes twice: for a local candidate and for a party. Point 7: Compensatory seats balance representation according to popular votes. Point 8: Germany and New Zealand have used this system successfully for decades. Point 9: This reform would strengthen the legitimacy of our parliamentary democracy. Point 10: I ask the government to hold a referendum on this vital question.","points":[{"point":1,"male_lines":["",""],"female_lines":["Mesdames et messieurs, notre système électoral actuel est démocratiquement défectueux.","Le scrutin uninominal majoritaire crée des distorsions flagrantes entre les votes et les sièges."]},{"point":2,"male_lines":["",""],"female_lines":["En deux mille dix-huit, un parti a obtenu dix pour cent des votes mais zéro député.","C'est pourquoi je propose l'adoption du scrutin proportionnel mixte compensatoire."]},{"point":3,"male_lines":["",""],"female_lines":["Ce système préserve la représentation locale tout en assurant la proportionnalité.","Chaque électeur vote deux fois : pour un candidat local et pour un parti."]},{"point":4,"male_lines":["",""],"female_lines":["Les sièges compensatoires équilibrent la représentation selon les votes populaires.","L'Allemagne et la Nouvelle-Zélande utilisent ce système avec succès depuis des décennies."]},{"point":5,"male_lines":["",""],"female_lines":["Cette réforme renforcerait la légitimité de notre démocratie parlementaire.","Je demande au gouvernement de tenir un référendum sur cette question vitale."]}]},{"id":33,"section":"G","theme":"Conférence : Changement climatique","question":"Quelle solution l'orateur privilégie-t-il ?","options":[{"id":"A","text":"L'interdiction totale des voitures","image_prompt":"Total car ban in city center"},{"id":"B","text":"La taxe carbone progressive","image_prompt":"Progressive carbon tax implementation"},{"id":"C","text":"La construction de murs anti-inondation","image_prompt":"Building flood protection walls"},{"id":"D","text":"L'interdiction de manger de la viande","image_prompt":"Meat consumption ban in restaurants"}],"correct":1,"transcript_fr":"Point 1 : Chers collègues, nous sommes à un tournant critique de l'histoire climatique. Point 2 : Les émissions mondiales continuent d'augmenter malgré les accords de Paris. Point 3 : Nous devons agir maintenant avec des mesures économiques audacieuses. Point 4 : Je propose l'instauration d'une taxe carbone progressive et redistributive. Point 5 : Cette taxe partirait de cinquante dollars la tonne pour atteindre deux cents dollars en dix ans. Point 6 : Les revenus seraient redistribués sous forme de chèque carbone aux citoyens. Point 7 : Les ménages modestes en sortiraient gagnants financièrement. Point 8 : Cette approche a fait ses preuves en Colombie-Britannique depuis deux mille huit. Point 9 : Elle incite les entreprises à innover vers la décarbonation. Point 10 : Sans action économique forte, nous condamnons les générations futures.","transcript_en":"Point 1: Dear colleagues, we are at a critical turning point in climate history. Point 2: Global emissions continue to rise despite the Paris agreements. Point 3: We must act now with bold economic measures. Point 4: I propose establishing a progressive and redistributive carbon tax. Point 5: This tax would start at fifty dollars per ton to reach two hundred dollars in ten years. Point 6: Revenues would be redistributed as carbon checks to citizens. Point 7: Modest households would come out financially ahead. Point 8: This approach has proven itself in British Columbia since two thousand eight. Point 9: It encourages companies to innovate toward decarbonization. Point 10: Without strong economic action, we condemn future generations.","points":[{"point":1,"male_lines":["Chers collègues, nous sommes à un tournant critique de l'histoire climatique.","Les émissions mondiales continuent d'augmenter malgré les accords de Paris."],"female_lines":["",""]},{"point":2,"male_lines":["Nous devons agir maintenant avec des mesures économiques audacieuses.","Je propose l'instauration d'une taxe carbone progressive et redistributive."],"female_lines":["",""]},{"point":3,"male_lines":["Cette taxe partirait de cinquante dollars la tonne pour atteindre deux cents dollars en dix ans.","Les revenus seraient redistribués sous forme de chèque carbone aux citoyens."],"female_lines":["",""]},{"point":4,"male_lines":["Les ménages modestes en sortiraient gagnants financièrement.","Cette approche a fait ses preuves en Colombie-Britannique depuis deux mille huit."],"female_lines":["",""]},{"point":5,"male_lines":["Elle incite les entreprises à innover vers la décarbonation.","Sans action économique forte, nous condamnons les générations futures."],"female_lines":["",""]}]},{"id":34,"section":"G","theme":"Conférence : Histoire du Québec","question":"Quel événement marque selon l'historienne le tournant national ?","options":[{"id":"A","text":"La bataille des Plaines d'Abraham","image_prompt":"Battle of the Plains of Abraham historical painting"},{"id":"B","text":"La Révolution tranquille","image_prompt":"Quiet Revolution era in Quebec with social changes"},{"id":"C","text":"La Crise d'octobre","image_prompt":"October Crisis with military presence in Montreal"},{"id":"D","text":"Le référendum de mille neuf cent quatre-vingt","image_prompt":"1980 Quebec referendum voting scene"}],"correct":1,"transcript_fr":"Point 1 : Bonjour, explorons ensemble les moments fondateurs de notre identité québécoise. Point 2 : Beaucoup citent la Conquête de mille sept cent cinquante-neuf comme moment charnière. Point 3 : Pourtant, je soutiens que la Révolution tranquille représente notre véritable tournant national. Point 4 : Entre mille neuf cent soixante et mille neuf cent soixante-dix, le Québec s'est métamorphosé. Point 5 : Nous sommes passés d'une société cléricale et rurale à une société laïque et moderne. Point 6 : La nationalisation de l'électricité et la création du CÉGEP ont transformé notre économie. Point 7 : L'affirmation du français comme langue officielle a consolidé notre identité. Point 8 : Cette décennie a vu naître notre État-providence moderne. Point 9 : Les Québécoises ont accédé à l'égalité juridique et sociale durant cette période. Point 10 : Sans la Révolution tranquille, le Québec contemporain n'existerait pas.","transcript_en":"Point 1: Hello, let's explore together the founding moments of our Quebec identity. Point 2: Many cite the Conquest of seventeen fifty-nine as the pivotal moment. Point 3: However, I maintain that the Quiet Revolution represents our true national turning point. Point 4: Between nineteen sixty and nineteen seventy, Quebec was transformed. Point 5: We moved from a clerical and rural society to a secular and modern society. Point 6: The nationalization of electricity and creation of CEGEP transformed our economy. Point 7: The affirmation of French as the official language consolidated our identity. Point 8: This decade saw the birth of our modern welfare state. Point 9: Quebec women achieved legal and social equality during this period. Point 10: Without the Quiet Revolution, contemporary Quebec would not exist.","points":[{"point":1,"male_lines":["",""],"female_lines":["Bonjour, explorons ensemble les moments fondateurs de notre identité québécoise.","Beaucoup citent la Conquête de mille sept cent cinquante-neuf comme moment charnière."]},{"point":2,"male_lines":["",""],"female_lines":["Pourtant, je soutiens que la Révolution tranquille représente notre véritable tournant national.","Entre mille neuf cent soixante et mille neuf cent soixante-dix, le Québec s'est métamorphosé."]},{"point":3,"male_lines":["",""],"female_lines":["Nous sommes passés d'une société cléricale et rurale à une société laïque et moderne.","La nationalisation de l'électricité et la création du CÉGEP ont transformé notre économie."]},{"point":4,"male_lines":["",""],"female_lines":["L'affirmation du français comme langue officielle a consolidé notre identité.","Cette décennie a vu naître notre État-providence moderne."]},{"point":5,"male_lines":["",""],"female_lines":["Les Québécoises ont accédé à l'égalité juridique et sociale durant cette période.","Sans la Révolution tranquille, le Québec contemporain n'existerait pas."]}]},{"id":35,"section":"G","theme":"Conférence : Santé mentale","question":"Quel est le principal obstacle selon le conférencier ?","options":[{"id":"A","text":"Le manque de médicaments","image_prompt":"Shortage of mental health medications in pharmacy"},{"id":"B","text":"La stigmatisation sociale","image_prompt":"Social stigma surrounding mental health issues"},{"id":"C","text":"Le manque de psychiatres","image_prompt":"Shortage of psychiatrists with long waiting lists"},{"id":"D","text":"Le coût des thérapies","image_prompt":"High cost of therapy sessions unaffordable"}],"correct":1,"transcript_fr":"Point 1 : Merci d'être présents pour cette discussion cruciale sur la santé mentale au travail. Point 2 : Une personne sur cinq vivra un trouble mental au cours de sa vie. Point 3 : Pourtant, soixante-dix pour cent ne consulteront jamais par peur du jugement. Point 4 : La stigmatisation reste le plus grand obstacle aux soins de santé mentale. Point 5 : Les employés craignent que cela n'affecte leur carrière ou leurs promotions. Point 6 : Nous devons créer des environnements où parler de dépression est aussi normal que parler d'un rhume. Point 7 : Les programmes d'aide aux employés doivent être véritablement confidentiels. Point 8 : Les gestionnaires nécessitent une formation pour reconnaître les signes de détresse. Point 9 : La prévention coûte moins cher que l'absentéisme chronique qui en résulte. Point 10 : Ensemble, brisons le silence qui entoure la souffrance psychologique.","transcript_en":"Point 1: Thank you for being here for this crucial discussion on mental health at work. Point 2: One in five people will experience a mental disorder in their lifetime. Point 3: Yet seventy percent will never consult for fear of judgment. Point 4: Stigmatization remains the greatest obstacle to mental health care. Point 5: Employees fear it will affect their career or promotions. Point 6: We must create environments where talking about depression is as normal as talking about a cold. Point 7: Employee assistance programs must be truly confidential. Point 8: Managers need training to recognize signs of distress. Point 9: Prevention costs less than the chronic absenteeism that results. Point 10: Together, let's break the silence surrounding psychological suffering.","points":[{"point":1,"male_lines":["Merci d'être présents pour cette discussion cruciale sur la santé mentale au travail.","Une personne sur cinq vivra un trouble mental au cours de sa vie."],"female_lines":["",""]},{"point":2,"male_lines":["Pourtant, soixante-dix pour cent ne consulteront jamais par peur du jugement.","La stigmatisation reste le plus grand obstacle aux soins de santé mentale."],"female_lines":["",""]},{"point":3,"male_lines":["Les employés craignent que cela n'affecte leur carrière ou leurs promotions.","Nous devons créer des environnements où parler de dépression est aussi normal que parler d'un rhume."],"female_lines":["",""]},{"point":4,"male_lines":["Les programmes d'aide aux employés doivent être véritablement confidentiels.","Les gestionnaires nécessitent une formation pour reconnaître les signes de détresse."],"female_lines":["",""]},{"point":5,"male_lines":["La prévention coûte moins cher que l'absentéisme chronique qui en résulte.","Ensemble, brisons le silence qui entoure la souffrance psychologique."],"female_lines":["",""]}]},{"id":36,"section":"H","theme":"Conférence : Philosophie politique","question":"Quel concept le philosophe défend-il ?","options":[{"id":"A","text":"Le libéralisme économique absolu","image_prompt":"Absolute economic liberalism with free market"},{"id":"B","text":"Le socialisme d'État autoritaire","image_prompt":"Authoritarian state socialism with government control"},{"id":"C","text":"Le libéralisme égalitaire","image_prompt":"Egalitarian liberalism with social justice"},{"id":"D","text":"L'anarchisme collectiviste","image_prompt":"Collectivist anarchism with no government"}],"correct":2,"transcript_fr":"Point 1 : Mes chers étudiants, examinons aujourd'hui la justice sociale dans les sociétés démocratiques. Point 2 : Le libéralisme classique prône la liberté individuelle sans égard pour les inégalités résultantes. Point 3 : Cette approche génère des disparités inacceptables qui minent la cohésion sociale. Point 4 : Je défends au contraire le libéralisme égalitaire ou libéralisme de gauche. Point 5 : Cette philosophie combine la liberté individuelle avec l'égalité des chances réelle. Point 6 : Elle reconnaît que les talents naturels sont une loterie morale arbitraire. Point 7 : L'État légitime peut donc redistribuer pour corriger les injustices du hasard social. Point 8 : Cela ne viole pas la liberté mais la contextualise dans une société juste. Point 9 : Rawls a montré que des citoyens rationnels choisiraient ce système derrière un voile d'ignorance. Point 10 : La justice exige donc des institutions qui bénéficient aux plus défavorisés.","transcript_en":"Point 1: My dear students, let's examine today social justice in democratic societies. Point 2: Classical liberalism advocates individual freedom without regard for resulting inequalities. Point 3: This approach generates unacceptable disparities that undermine social cohesion. Point 4: I defend on the contrary egalitarian liberalism or left liberalism. Point 5: This philosophy combines individual freedom with real equality of opportunity. Point 6: It recognizes that natural talents are an arbitrary moral lottery. Point 7: The legitimate State can therefore redistribute to correct social chance injustices. Point 8: This does not violate freedom but contextualizes it in a just society. Point 9: Rawls showed that rational citizens would choose this system behind a veil of ignorance. Point 10: Justice therefore requires institutions that benefit the least advantaged.","points":[{"point":1,"male_lines":["Mes chers étudiants, examinons aujourd'hui la justice sociale dans les sociétés démocratiques.","Le libéralisme classique prône la liberté individuelle sans égard pour les inégalités résultantes."],"female_lines":["",""]},{"point":2,"male_lines":["Cette approche génère des disparités inacceptables qui minent la cohésion sociale.","Je défends au contraire le libéralisme égalitaire ou libéralisme de gauche."],"female_lines":["",""]},{"point":3,"male_lines":["Cette philosophie combine la liberté individuelle avec l'égalité des chances réelle.","Elle reconnaît que les talents naturels sont une loterie morale arbitraire."],"female_lines":["",""]},{"point":4,"male_lines":["L'État légitime peut donc redistribuer pour corriger les injustices du hasard social.","Cela ne viole pas la liberté mais la contextualise dans une société juste."],"female_lines":["",""]},{"point":5,"male_lines":["Rawls a montré que des citoyens rationnels choisiraient ce système derrière un voile d'ignorance.","La justice exige donc des institutions qui bénéficient aux plus défavorisés."],"female_lines":["",""]}]},{"id":37,"section":"H","theme":"Conférence : Neurosciences","question":"Quelle découverte l'oratrice présente-t-elle ?","options":[{"id":"A","text":"Que le cerveau ne change jamais après vingt ans","image_prompt":"Brain that never changes after age twenty"},{"id":"B","text":"Que la mémoire est localisée dans une seule région","image_prompt":"Memory localized in single brain region"},{"id":"C","text":"La neuroplasticité tout au long de la vie","image_prompt":"Brain neuroplasticity throughout lifetime"},{"id":"D","text":"Que les émotions n'ont pas de base biologique","image_prompt":"Emotions without biological basis theory"}],"correct":2,"transcript_fr":"Point 1 : Bonjour, partageons aujourd'hui une révolution dans notre compréhension du cerveau. Point 2 : Pendant des décennies, nous croyions que le cerveau adulte était figé et immuable. Point 3 : Les dernières recherches prouvent le contraire : le cerveau se remodèle constamment. Point 4 : Cette capacité s'appelle la neuroplasticité et persiste jusqu'à un âge avancé. Point 5 : Chaque fois que vous apprenez quelque chose de nouveau, vos neurones créent des connexions. Point 6 : Même après un accident vasculaire cérébral, le cerveau peut réorganiser ses fonctions. Point 7 : L'apprentissage d'une langue seconde augmente la densité de la matière grise. Point 8 : La méditation modifie structurellement les régions liées à l'attention et à la compassion. Point 9 : Ces découvertes bouleversent notre approche de l'éducation et de la rééducation. Point 10 : Il n'est jamais trop tard pour apprendre, changer ou guérir.","transcript_en":"Point 1: Hello, let's share today a revolution in our understanding of the brain. Point 2: For decades, we believed the adult brain was fixed and immutable. Point 3: Latest research proves the opposite: the brain constantly remodels itself. Point 4: This capacity is called neuroplasticity and persists into advanced age. Point 5: Every time you learn something new, your neurons create connections. Point 6: Even after a stroke, the brain can reorganize its functions. Point 7: Learning a second language increases grey matter density. Point 8: Meditation structurally modifies regions linked to attention and compassion. Point 9: These discoveries revolutionize our approach to education and rehabilitation. Point 10: It is never too late to learn, change or heal.","points":[{"point":1,"male_lines":["",""],"female_lines":["Bonjour, partageons aujourd'hui une révolution dans notre compréhension du cerveau.","Pendant des décennies, nous croyions que le cerveau adulte était figé et immuable."]},{"point":2,"male_lines":["",""],"female_lines":["Les dernières recherches prouvent le contraire : le cerveau se remodèle constamment.","Cette capacité s'appelle la neuroplasticité et persiste jusqu'à un âge avancé."]},{"point":3,"male_lines":["",""],"female_lines":["Chaque fois que vous apprenez quelque chose de nouveau, vos neurones créent des connexions.","Même après un accident vasculaire cérébral, le cerveau peut réorganiser ses fonctions."]},{"point":4,"male_lines":["",""],"female_lines":["L'apprentissage d'une langue seconde augmente la densité de la matière grise.","La méditation modifie structurellement les régions liées à l'attention et à la compassion."]},{"point":5,"male_lines":["",""],"female_lines":["Ces découvertes bouleversent notre approche de l'éducation et de la rééducation.","Il n'est jamais trop tard pour apprendre, changer ou guérir."]}]},{"id":38,"section":"H","theme":"Conférence : Économie comportementale","question":"Quel biais cognitif l'orateur explique-t-il ?","options":[{"id":"A","text":"L'effet de halo","image_prompt":"Halo effect bias in judgment"},{"id":"B","text":"L'aversion aux pertes","image_prompt":"Loss aversion bias in decision making"},{"id":"C","text":"L'effet de groupe","image_prompt":"Group effect conformity bias"},{"id":"D","text":"La surconfiance","image_prompt":"Overconfidence bias in predictions"}],"correct":1,"transcript_fr":"Point 1 : Bienvenue dans cette exploration des irrationalités économiques humaines. Point 2 : Les modèles classiques supposent que nous sommes des calculateurs rationnels optimisant nos gains. Point 3 : La réalité est bien différente : nous sommes émotionnellement attachés à nos possessions. Point 4 : Le biais de l'aversion aux pertes démontre que perdre fait deux fois plus mal que gagner fait plaisir. Point 5 : Un investisseur retient trop longtemps des actions en baisse pour éviter de réaliser une perte. Point 6 : Un consommateur refuse de vendre sa maison en dessous du prix d'achat même si le marché a chuté. Point 7 : Ce biais explique pourquoi les négociations commerciales peinent à converger. Point 8 : Chaque partie surestime ce qu'elle possède et sous-estime ce qu'elle pourrait acquérir. Point 9 : Reconnaître ce biais permet de prendre de meilleures décisions financières. Point 10 : La rationalité commence par accepter nos irrationnalités innées.","transcript_en":"Point 1: Welcome to this exploration of human economic irrationalities. Point 2: Classical models assume we are rational calculators optimizing our gains. Point 3: Reality is quite different: we are emotionally attached to our possessions. Point 4: The loss aversion bias demonstrates that losing hurts twice as much as winning feels good. Point 5: An investor holds falling stocks too long to avoid realizing a loss. Point 6: A consumer refuses to sell their house below purchase price even if the market has dropped. Point 7: This bias explains why commercial negotiations struggle to converge. Point 8: Each party overestimates what they own and underestimates what they could acquire. Point 9: Recognizing this bias allows making better financial decisions. Point 10: Rationality begins with accepting our innate irrationalities.","points":[{"point":1,"male_lines":["Bienvenue dans cette exploration des irrationalités économiques humaines.","Les modèles classiques supposent que nous sommes des calculateurs rationnels optimisant nos gains."],"female_lines":["",""]},{"point":2,"male_lines":["La réalité est bien différente : nous sommes émotionnellement attachés à nos possessions.","Le biais de l'aversion aux pertes démontre que perdre fait deux fois plus mal que gagner fait plaisir."],"female_lines":["",""]},{"point":3,"male_lines":["Un investisseur retient trop longtemps des actions en baisse pour éviter de réaliser une perte.","Un consommateur refuse de vendre sa maison en dessous du prix d'achat même si le marché a chuté."],"female_lines":["",""]},{"point":4,"male_lines":["Ce biais explique pourquoi les négociations commerciales peinent à converger.","Chaque partie surestime ce qu'elle possède et sous-estime ce qu'elle pourrait acquérir."],"female_lines":["",""]},{"point":5,"male_lines":["Reconnaître ce biais permet de prendre de meilleures décisions financières.","La rationalité commence par accepter nos irrationnalités innées."],"female_lines":["",""]}]},{"id":39,"section":"H","theme":"Conférence : Anthropologie","question":"Quelle thèse défend l'anthropologue ?","options":[{"id":"A","text":"Que les cultures sont hiérarchiquement classables","image_prompt":"Cultures hierarchically ranked by anthropologist"},{"id":"B","text":"Que le chamanisme est une superstition primitive","image_prompt":"Shamanism as primitive superstition theory"},{"id":"C","text":"Le relativisme culturel radical","image_prompt":"Radical cultural relativism with diverse cultures"},{"id":"D","text":"L'uniformisation culturelle mondiale","image_prompt":"Global cultural homogenization with same brands"}],"correct":2,"transcript_fr":"Point 1 : Chers collègues, remettons en question notre posture d'observation culturelle. Point 2 : L'anthropologie coloniale classifiait les sociétés du primitif au civilisé. Point 3 : Cette approche ethnocentrique est scientifiquement et moralement insoutenable. Point 4 : Je défends le relativisme culturel radical : chaque culture doit être comprise dans ses propres termes. Point 5 : Ce qui semble irrationnel à l'extérieur possède une logique interne cohérente. Point 6 : La sorcellerie n'est pas une erreur de pensée mais un système de relations sociales complexe. Point 7 : Les rituels d'initiation ne sont pas barbares mais des mécanismes d'intégration communautaire. Point 8 : Comprendre ne signifie pas approuver, mais suspendre le jugement moral initial. Point 9 : Cette posture épistémologique enrichit notre compréhension de la diversité humaine. Point 10 : Respecter l'altérité culturelle est la base de toute anthropologie digne de ce nom.","transcript_en":"Point 1: Dear colleagues, let's question our posture of cultural observation. Point 2: Colonial anthropology classified societies from primitive to civilized. Point 3: This ethnocentric approach is scientifically and morally unsustainable. Point 4: I defend radical cultural relativism: each culture must be understood on its own terms. Point 5: What seems irrational from the outside possesses a coherent internal logic. Point 6: Witchcraft is not a thinking error but a complex system of social relations. Point 7: Initiation rituals are not barbaric but community integration mechanisms. Point 8: Understanding does not mean approving, but suspending initial moral judgment. Point 9: This epistemological posture enriches our understanding of human diversity. Point 10: Respecting cultural alterity is the basis of any anthropology worthy of the name.","points":[{"point":1,"male_lines":["",""],"female_lines":["Chers collègues, remettons en question notre posture d'observation culturelle.","L'anthropologie coloniale classifiait les sociétés du primitif au civilisé."]},{"point":2,"male_lines":["",""],"female_lines":["Cette approche ethnocentrique est scientifiquement et moralement insoutenable.","Je défends le relativisme culturel radical : chaque culture doit être comprise dans ses propres termes."]},{"point":3,"male_lines":["",""],"female_lines":["Ce qui semble irrationnel à l'extérieur possède une logique interne cohérente.","La sorcellerie n'est pas une erreur de pensée mais un système de relations sociales complexe."]},{"point":4,"male_lines":["",""],"female_lines":["Les rituels d'initiation ne sont pas barbares mais des mécanismes d'intégration communautaire.","Comprendre ne signifie pas approuver, mais suspendre le jugement moral initial."]},{"point":5,"male_lines":["",""],"female_lines":["Cette posture épistémologique enrichit notre compréhension de la diversité humaine.","Respecter l'altérité culturelle est la base de toute anthropologie digne de ce nom."]}]},{"id":40,"section":"H","theme":"Conférence : Physique quantique","question":"Quel phénomène l'orateur explique-t-il ?","options":[{"id":"A","text":"La relativité générale d'Einstein","image_prompt":"Einstein's general relativity with spacetime curvature"},{"id":"B","text":"L'intrication quantique","image_prompt":"Quantum entanglement with connected particles"},{"id":"C","text":"La fusion nucléaire","image_prompt":"Nuclear fusion with sun energy production"},{"id":"D","text":"La théorie des cordes","image_prompt":"String theory with vibrating strings"}],"correct":1,"transcript_fr":"Point 1 : Bienvenue dans l'univers étrange de la mécanique quantique. Point 2 : Imaginez deux particules créées ensemble puis séparées par des années-lumière. Point 3 : Classiquement, elles devraient être indépendantes à cette distance. Point 4 : Or, la mesure de l'une détermine instantanément l'état de l'autre. Point 5 : Ce phénomène d'intrication défie notre intuition d'espace et de temps. Point 6 : Einstein l'appelait effet fantôme à action à distance effrayante. Point 7 : Pourtant, des milliers d'expériences confirment cette réalité quantique. Point 8 : L'intrication est aujourd'hui exploitée pour la cryptographie quantique inviolable. Point 9 : Elle pourrait révolutionner l'informatique avec les ordinateurs quantiques. Point 10 : La nature est fondamentalement plus étrange que nous ne l'imaginions.","transcript_en":"Point 1: Welcome to the strange universe of quantum mechanics. Point 2: Imagine two particles created together then separated by light-years. Point 3: Classically, they should be independent at this distance. Point 4: Yet, measuring one instantly determines the state of the other. Point 5: This entanglement phenomenon defies our intuition of space and time. Point 6: Einstein called it spooky action at a distance. Point 7: Yet thousands of experiments confirm this quantum reality. Point 8: Entanglement is now exploited for unbreakable quantum cryptography. Point 9: It could revolutionize computing with quantum computers. Point 10: Nature is fundamentally stranger than we imagined.","points":[{"point":1,"male_lines":["Bienvenue dans l'univers étrange de la mécanique quantique.","Imaginez deux particules créées ensemble puis séparées par des années-lumière."],"female_lines":["",""]},{"point":2,"male_lines":["Classiquement, elles devraient être indépendantes à cette distance.","Or, la mesure de l'une détermine instantanément l'état de l'autre."],"female_lines":["",""]},{"point":3,"male_lines":["Ce phénomène d'intrication défie notre intuition d'espace et de temps.","Einstein l'appelait effet fantôme à action à distance effrayante."],"female_lines":["",""]},{"point":4,"male_lines":["Pourtant, des milliers d'expériences confirment cette réalité quantique.","L'intrication est aujourd'hui exploitée pour la cryptographie quantique inviolable."],"female_lines":["",""]},{"point":5,"male_lines":["Elle pourrait révolutionner l'informatique avec les ordinateurs quantiques.","La nature est fondamentalement plus étrange que nous ne l'imaginions."],"female_lines":["",""]}]}]`);export{e as default};
